  36→struct LakeFsObserver {
  37→    workspace_root: PathBuf,
  38→    journal: Arc<dyn Journal>,
  39→    blob_store: Arc<lago_store::BlobStore>,
  40→}
  41→
  42→#[async_trait::async_trait]
  43→impl arcan_aios_adapters::tools::ToolHarnessObserver for LakeFsObserver {
  44→    async fn post_execute(&self, session_id: String, _tool_name: String) {
  45→        // We skip memory tools since they don't modify the FS directly, and bash since we might want more granular control, but for now we trace everything.
  46→        let sess_id = SessionId::from_string(session_id.clone());
  47→        let branch_id = BranchId::from_string("main");
  48→
  49→        let events = match self
  50→            .journal
  51→            .read(EventQuery::new().session(lago_core::SessionId::from_string(session_id)))
  52→            .await
  53→        {
  54→            Ok(events) => events,
  55→            Err(e) => {
  56→                tracing::warn!(%e, "LakeFsObserver: failed to read journal");
  57→                return;
  58→            }
  59→        };
  60→
  61→        let mut proj = ManifestProjection::new();
  62→        for e in events {
  63→            if e.branch_id == branch_id {
  64→                let _ = proj.on_event(&e);
  65→            }
  66→        }
  67→
  68→        let current_manifest = proj.manifest().clone();
  69→
  70→        // Run the synchronous snapshot + diff on a blocking thread to avoid
  71→        // stalling the tokio worker (the walk/hash can take seconds on large workspaces).
  72→        let workspace_root = self.workspace_root.clone();
  73→        let blob_store = self.blob_store.clone();
  74→        let snapshot_result = tokio::task::spawn_blocking(move || {
  75→            let new_manifest = lago_fs::snapshot(&workspace_root, &current_manifest, &blob_store)?;
  76→            let diffs = lago_fs::diff(&current_manifest, &new_manifest);
  77→            Ok::<_, lago_core::LagoError>(diffs)
  78→        })
  79→        .await;
  80→
  81→        let diffs = match snapshot_result {
  82→            Ok(Ok(d)) => d,
  83→            Ok(Err(e)) => {
  84→                tracing::warn!(%e, "LakeFsObserver: failed to snapshot workspace");
  85→                return;
  86→            }
  87→            Err(e) => {
  88→                tracing::warn!(%e, "LakeFsObserver: snapshot task panicked");
  89→                return;
  90→            }
  91→        };
  92→        if diffs.is_empty() {
  93→            return;
  94→        }
  95→
  96→        tracing::info!(
  97→            diff_count = diffs.len(),
  98→            "LakeFsObserver: workspace changed, emitting events"
  99→        );
 100→
 101→        for diff in diffs {
 102→            let payload = match diff {
 103→                DiffEntry::Added { path, entry } => EventPayload::FileWrite {
 104→                    path,
 105→                    blob_hash: entry.blob_hash.into(),
 106→                    size_bytes: entry.size_bytes,
 107→                    content_type: entry.content_type,
 108→                },
 109→                DiffEntry::Modified {
 110→                    path, new: entry, ..
 111→                } => EventPayload::FileWrite {
 112→                    path,
 113→                    blob_hash: entry.blob_hash.into(),
 114→                    size_bytes: entry.size_bytes,
 115→                    content_type: entry.content_type,
 116→                },
 117→                DiffEntry::Removed { path, .. } => EventPayload::FileDelete { path },
 118→            };
 119→
 120→            let envelope = EventEnvelope {
 121→                event_id: EventId::new(),
 122→                session_id: sess_id.clone(),
 123→                branch_id: branch_id.clone(),
 124→                run_id: None,
 125→                seq: 0,
 126→                timestamp: EventEnvelope::now_micros(),
 127→                parent_id: None,
 128→                payload,
 129→                metadata: std::collections::HashMap::new(),
 130→                schema_version: 1,
 131→            };
 132→
 133→            if let Err(e) = self.journal.append(envelope).await {
 134→                tracing::warn!(%e, "LakeFsObserver: failed to append event");
 135→            }
 136→        }
 137→    }
 138→}
