 264→async fn shutdown_signal() {
 265→    let ctrl_c = tokio::signal::ctrl_c();
 266→
 267→    #[cfg(unix)]
 268→    {
 269→        let mut sigterm = tokio::signal::unix::signal(tokio::signal::unix::SignalKind::terminate())
 270→            .expect("failed to install SIGTERM handler");
 271→        tokio::select! {
 272→            _ = ctrl_c => {},
 273→            _ = sigterm.recv() => {},
 274→        }
 275→    }
 276→
 277→    #[cfg(not(unix))]
 278→    {
 279→        ctrl_c.await.ok();
 280→    }
 281→
 282→    tracing::info!("Received shutdown signal, draining connections...");
 283→}
