 285→fn resolve_data_dir(data_dir: &PathBuf) -> anyhow::Result<PathBuf> {
 286→    let workspace_root = std::env::current_dir()?;
 287→    Ok(if data_dir.is_relative() {
 288→        workspace_root.join(data_dir)
 289→    } else {
 290→        data_dir.clone()
 291→    })
 292→}
