 311→/// Resolve session via the daemon's HTTP API first, falling back to local hints.
 312→/// This avoids opening the journal (which would conflict with the daemon's redb lock).
 313→async fn resolve_session(
 314→    data_dir: &Path,
 315→    requested: Option<String>,
 316→    base_url: Option<&str>,
 317→) -> String {
 318→    if let Some(session) = requested {
 319→        return session;
 320→    }
 321→
 322→    if let Some(session) = read_last_session_hint(data_dir) {
 323→        return session;
 324→    }
 325→
 326→    // Try the HTTP API if a daemon URL is available (avoids redb lock conflict).
 327→    if let Some(url) = base_url {
 328→        if let Some(session) = cli_run::resolve_session_via_api(url).await {
 329→            return session;
 330→        }
 331→    }
 332→
 333→    "default".to_owned()
 334→}
