 336→/// Try to create an OpenAI provider from stored OAuth credentials.
 337→fn try_openai_oauth_provider() -> Option<Arc<dyn Provider>> {
 338→    let tokens = arcan_provider::oauth::load_tokens("openai").ok()?;
 339→    let credential = Arc::new(arcan_provider::oauth::OAuthCredential::openai(tokens));
 340→    let model = std::env::var("OPENAI_MODEL").unwrap_or_else(|_| "gpt-4o".to_string());
 341→    let config = arcan_provider::openai::OpenAiConfig::from_oauth(credential, model.clone());
 342→    tracing::info!(%model, "Provider: OpenAI (OAuth)");
 343→    Some(Arc::new(
 344→        arcan_provider::openai::OpenAiCompatibleProvider::new(config),
 345→    ))
 346→}
