 415→fn run_serve(
 416→    data_dir: &Path,
 417→    resolved: &ResolvedConfig,
 418→    console_dir: Option<PathBuf>,
 419→) -> anyhow::Result<()> {
 420→    let workspace_root = std::env::current_dir()?;
 421→
 422→    // --- Lago persistence ---
 423→    let journal_path = data_dir.join("journal.redb");
 424→    let blobs_path = data_dir.join("blobs");
 425→    std::fs::create_dir_all(&blobs_path)?;
 426→
 427→    tracing::info!(
 428→        workspace = %workspace_root.display(),
 429→        journal = %journal_path.display(),
 430→        blobs = %blobs_path.display(),
 431→        provider = %resolved.provider,
 432→        model = ?resolved.model,
 433→        port = resolved.port,
 434→        "Starting arcan"
 435→    );
 436→
 437→    let journal = RedbJournal::open(&journal_path)?;
 438→    let _blob_store = Arc::new(lago_store::BlobStore::open(&blobs_path)?);
 439→    let journal: Arc<dyn lago_core::Journal> = Arc::new(journal);
 440→
 441→    // --- Policies ---
 442→    let fs_policy = FsPolicy::new(workspace_root.clone());
 443→    let sandbox_policy = SandboxPolicy {
 444→        workspace_root: workspace_root.clone(),
 445→        shell_enabled: true,
 446→        network: NetworkPolicy::AllowAll,
 447→        allowed_env: BTreeSet::new(),
 448→        max_execution_ms: 10_000,
 449→        max_stdout_bytes: 1024 * 1024,
 450→        max_stderr_bytes: 1024 * 1024,
 451→        max_processes: 10,
 452→        max_memory_mb: 512,
 453→    };
 454→
 455→    // --- Tools ---
 456→    let mut registry = ToolRegistry::default();
 457→    registry.register(ReadFileTool::new(fs_policy.clone()));
 458→    registry.register(WriteFileTool::new(fs_policy.clone()));
 459→    registry.register(ListDirTool::new(fs_policy.clone()));
 460→    registry.register(EditFileTool::new(fs_policy.clone()));
 461→    registry.register(GlobTool::new(fs_policy.clone()));
 462→    registry.register(GrepTool::new(fs_policy));
 463→
 464→    let runner = Box::new(LocalCommandRunner);
 465→    registry.register(BashTool::new(sandbox_policy, runner));
 466→
 467→    let memory_dir = data_dir.join("memory");
 468→    std::fs::create_dir_all(&memory_dir)?;
 469→    registry.register(ReadMemoryTool::new(memory_dir.clone()));
 470→    registry.register(WriteMemoryTool::new(memory_dir));
 471→
 472→    // --- Governed memory tools (event-sourced via Lago) ---
 473→    let memory_projection = Arc::new(RwLock::new(MemoryProjection::new()));
 474→    registry.register(MemoryQueryTool::new(memory_projection));
 475→    registry.register(MemoryProposeTool::new(journal.clone()));
 476→    registry.register(MemoryCommitTool::new(journal.clone()));
 477→
 478→    // --- Spaces distributed networking (opt-in) ---
 479→    #[cfg(feature = "spaces")]
 480→    {
 481→        let spaces_port: Arc<dyn arcan_spaces::SpacesPort> =
 482→            Arc::new(arcan_spaces::MockSpacesClient::default_hub());
 483→        arcan_spaces::register_spaces_tools(&mut registry, spaces_port);
 484→    }
 485→
 486→    // --- Provider ---
 487→    let provider = build_provider(resolved)?;
 488→
 489→    // Swappable handle for live provider switching
 490→    let provider_handle: arcan_core::runtime::SwappableProviderHandle =
 491→        Arc::new(std::sync::RwLock::new(provider));
 492→    let provider_factory: Arc<dyn arcan_core::runtime::ProviderFactory> =
 493→        Arc::new(factory::ArcanProviderFactory);
 494→
 495→    // --- Canonical aiOS runtime adapters ---
 496→    let event_store: Arc<dyn EventStorePort> =
 497→        Arc::new(LagoAiosEventStoreAdapter::new(journal.clone()));
 498→    // Shared handle: starts empty, filled after runtime creation.
 499→    let streaming_sender: StreamingSenderHandle = Arc::new(std::sync::Mutex::new(None));
 500→    let provider_adapter: Arc<dyn ModelProviderPort> = Arc::new(ArcanProviderAdapter::from_handle(
 501→        provider_handle.clone(),
 502→        registry.definitions(),
 503→        streaming_sender.clone(),
 504→    ));
 505→    let observer = Arc::new(LakeFsObserver {
 506→        workspace_root: workspace_root.clone(),
 507→        journal: journal.clone(),
 508→        blob_store: _blob_store,
 509→    });
 510→    let tool_harness: Arc<dyn ToolHarnessPort> =
 511→        Arc::new(ArcanHarnessAdapter::new(registry).with_observer(observer));
 512→    let policy_gate: Arc<dyn PolicyGatePort> =
 513→        Arc::new(ArcanPolicyAdapter::new(aios_protocol::PolicySet::default()));
 514→    let approvals: Arc<dyn ApprovalPort> = Arc::new(ArcanApprovalAdapter::new());
 515→
 516→    let runtime = Arc::new(KernelRuntime::new(
 517→        RuntimeConfig::new(data_dir.to_path_buf()),
 518→        event_store,
 519→        provider_adapter,
 520→        tool_harness,
 521→        approvals,
 522→        policy_gate,
 523→    ));
 524→
 525→    // Wire the broadcast sender now that the runtime exists.
 526→    *streaming_sender.lock().unwrap() = Some(runtime.event_sender());
 527→
 528→    // Build provider stack and blocking HTTP clients before entering Tokio runtime.
 529→    let data_dir_owned = data_dir.to_path_buf();
 530→    let port = resolved.port;
 531→    let tokio_runtime = tokio::runtime::Builder::new_multi_thread()
 532→        .enable_all()
 533→        .build()?;
 534→
 535→    tokio_runtime.block_on(async move {
 536→        // --- HTTP Server ---
 537→        let mut router = create_canonical_router(runtime, provider_handle, provider_factory);
 538→
 539→        // --- Console UI ---
 540→        #[cfg(feature = "console")]
 541→        {
 542→            let console_config = arcan_console::ConsoleConfig {
 543→                override_dir: console_dir,
 544→            };
 545→            router = router.nest("/console", arcan_console::console_router(console_config));
 546→        }
 547→
 548→        // --- CORS (for dev mode with separate Vite server) ---
 549→        let cors = tower_http::cors::CorsLayer::permissive();
 550→        let router = router.layer(cors);
 551→
 552→        let addr = std::net::SocketAddr::from(([127, 0, 0, 1], port));
 553→        let listener = TcpListener::bind(addr).await?;
 554→
 555→        tracing::info!(%addr, "Listening");
 556→        axum::serve(listener, router)
 557→            .with_graceful_shutdown(shutdown_signal())
 558→            .await?;
 559→
 560→        // Clean up PID file on graceful shutdown.
 561→        daemon::remove_pid_file(&data_dir_owned);
 562→
 563→        tracing::info!("Server shut down gracefully");
 564→        Ok(())
 565→    })
 566→}
