 568→async fn run_chat(
 569→    data_dir: PathBuf,
 570→    resolved: &ResolvedConfig,
 571→    session: Option<String>,
 572→    url: Option<String>,
 573→) -> anyhow::Result<()> {
 574→    // Ensure daemon is running first to avoid redb lock conflicts.
 575→    let base_url = match url {
 576→        Some(u) => u,
 577→        None => {
 578→            daemon::ensure_daemon(
 579→                &data_dir,
 580→                resolved.port,
 581→                Some(resolved.provider.as_str()).filter(|s| !s.is_empty()),
 582→                resolved.model.as_deref(),
 583→            )
 584→            .await?
 585→        }
 586→    };
 587→
 588→    // Resolve session via API (no direct journal access).
 589→    let session = resolve_session(&data_dir, session, Some(&base_url)).await;
 590→    tracing::info!(session = %session, "launching TUI");
 591→
 592→    if let Err(error) = persist_last_session_hint(&data_dir, &session) {
 593→        tracing::warn!(%error, "failed to persist last_session hint");
 594→    }
 595→
 596→    arcan_tui::run_tui(base_url, session).await
 597→}
