 599→async fn run_message(
 600→    data_dir: PathBuf,
 601→    resolved: &ResolvedConfig,
 602→    message: String,
 603→    session: Option<String>,
 604→    url: Option<String>,
 605→    json_output: bool,
 606→) -> anyhow::Result<()> {
 607→    // Ensure daemon is running first.
 608→    let base_url = match url {
 609→        Some(u) => u,
 610→        None => {
 611→            daemon::ensure_daemon(
 612→                &data_dir,
 613→                resolved.port,
 614→                Some(resolved.provider.as_str()).filter(|s| !s.is_empty()),
 615→                resolved.model.as_deref(),
 616→            )
 617→            .await?
 618→        }
 619→    };
 620→
 621→    // Resolve session via API (no direct journal access).
 622→    let session = resolve_session(&data_dir, session, Some(&base_url)).await;
 623→
 624→    if let Err(error) = persist_last_session_hint(&data_dir, &session) {
 625→        tracing::warn!(%error, "failed to persist last_session hint");
 626→    }
 627→
 628→    let exit_code = cli_run::run_cli(
 629→        &base_url,
 630→        &session,
 631→        &message,
 632→        json_output,
 633→        resolved.model.as_deref(),
 634→    )
 635→    .await?;
 636→    if exit_code != 0 {
 637→        std::process::exit(exit_code);
 638→    }
 639→    Ok(())
 640→}
