 651→                std::fs::write(&path, config::default_config_content())?;
 652→                println!("Created config: {}", path.display());
 653→            }
 654→        }
 655→        ConfigAction::Set { key, value } => {
 656→            let mut cfg = config::load_config(data_dir);
 657→            cfg.set_key(&key, &value)
 658→                .map_err(|e| anyhow::anyhow!("{e}"))?;
 659→            config::save_config(data_dir, &cfg)?;
 660→            println!("{key} = {value}");
 661→        }
 662→        ConfigAction::Get { key } => {
 663→            let cfg = config::load_config(data_dir);
 664→            match cfg.get_key(&key) {
 665→                Some(value) => println!("{value}"),
 666→                None => println!("(not set)"),
 667→            }
 668→        }
 669→        ConfigAction::List => {
 670→            let cfg = config::load_config(data_dir);
 671→            let content = toml::to_string_pretty(&cfg)
 672→                .map_err(|e| anyhow::anyhow!("failed to serialize config: {e}"))?;
 673→            if content.trim().is_empty()
 674→                || content.trim() == "[defaults]\n\n[agent]"
 675→                || content
 676→                    .lines()
 677→                    .all(|l| l.trim().is_empty() || l.starts_with('['))
 678→            {
