 181→    tools: ToolRegistry,
 182→    middlewares: Vec<Arc<dyn Middleware>>,
 183→    config: OrchestratorConfig,
 184→}
 185→
 186→impl Orchestrator {
 187→    pub fn new(
 188→        provider: Arc<dyn Provider>,
 189→        tools: ToolRegistry,
 190→        middlewares: Vec<Arc<dyn Middleware>>,
 191→        config: OrchestratorConfig,
 192→    ) -> Self {
 193→        Self {
 194→            provider: Arc::new(std::sync::RwLock::new(provider)),
 195→            tools,
 196→            middlewares,
 197→            config,
 198→        }
 199→    }
 200→
 201→    /// Swap the active provider at runtime. Returns the name of the new provider.
 202→    pub fn swap_provider(&self, new_provider: Arc<dyn Provider>) -> String {
 203→        let name = new_provider.name().to_string();
 204→        let mut guard = self.provider.write().expect("provider lock poisoned");
 205→        *guard = new_provider;
 206→        name
 207→    }
 208→
 209→    /// Get the current provider name.
 210→    pub fn provider_name(&self) -> String {
 211→        let guard = self.provider.read().expect("provider lock poisoned");
 212→        guard.name().to_string()
 213→    }
 214→
 215→    pub fn run(&self, input: RunInput, event_handler: impl FnMut(AgentEvent)) -> RunOutput {
 216→        self.run_cancellable(input, None, event_handler)
 217→    }
 218→
 219→    /// Run the orchestrator loop with an optional cancellation flag.
 220→    ///
 221→    /// If `cancel` is provided and set to `true` during execution,
 222→    /// the loop will stop at the next iteration boundary.
 223→    pub fn run_cancellable(
 224→        &self,
 225→        input: RunInput,
 226→        cancel: Option<&Arc<AtomicBool>>,
 227→        mut event_handler: impl FnMut(AgentEvent),
 228→    ) -> RunOutput {
 229→        let mut events = Vec::new();
 230→        let mut messages = input.messages;
 231→        let mut state = input.state;
 232→        let mut final_answer: Option<String> = None;
 233→        let mut stop_reason = RunStopReason::BudgetExceeded;
 234→        let mut total_iterations = 0;
 235→        let mut total_usage = TokenUsage::default();
 236→
 237→        // Acquire provider reference for this run
 238→        let provider = self
 239→            .provider
 240→            .read()
 241→            .expect("provider lock poisoned")
 242→            .clone();
 243→
 244→        let start_event = AgentEvent::RunStarted {
 245→            run_id: input.run_id.clone(),
 246→            session_id: input.session_id.clone(),
 247→            provider: provider.name().to_string(),
 248→            max_iterations: self.config.max_iterations,
 249→        };
 250→        event_handler(start_event.clone());
 251→        events.push(start_event);
 252→
 253→        for iteration in 1..=self.config.max_iterations {
 254→            // Check cancellation at each iteration boundary
 255→            if let Some(flag) = cancel {
 256→                if flag.load(Ordering::Relaxed) {
 257→                    stop_reason = RunStopReason::Cancelled;
 258→                    let err_event = AgentEvent::RunErrored {
 259→                        run_id: input.run_id.clone(),
 260→                        session_id: input.session_id.clone(),
 261→                        error: "run cancelled".to_string(),
 262→                    };
 263→                    event_handler(err_event.clone());
 264→                    events.push(err_event);
 265→                    break;
 266→                }
 267→            }
 268→
 269→            total_iterations = iteration;
 270→            let iter_event = AgentEvent::IterationStarted {
 271→                run_id: input.run_id.clone(),
 272→                session_id: input.session_id.clone(),
 273→                iteration,
 274→            };
 275→            event_handler(iter_event.clone());
 276→            events.push(iter_event);
 277→
 278→            // Context window compaction: trim messages before sending to provider
 279→            if let Some(ref ctx_config) = self.config.context {
 280→                if let Some(result) = compact_messages(&messages, ctx_config) {
 281→                    let compact_event = AgentEvent::ContextCompacted {
 282→                        run_id: input.run_id.clone(),
 283→                        session_id: input.session_id.clone(),
 284→                        iteration,
 285→                        dropped_count: result.dropped_count,
 286→                        tokens_before: result.tokens_before,
 287→                        tokens_after: result.tokens_after,
 288→                    };
 289→                    event_handler(compact_event.clone());
 290→                    events.push(compact_event);
 291→                    messages = result.messages;
 292→                }
 293→            }
 294→
 295→            let provider_request = ProviderRequest {
 296→                run_id: input.run_id.clone(),
 297→                session_id: input.session_id.clone(),
 298→                iteration,
 299→                messages: messages.clone(),
 300→                tools: self.tools.definitions(),
 301→                state: state.clone(),
 302→            };
 303→
 304→            if let Err(err) = self.run_before_model(&provider_request) {
 305→                stop_reason = RunStopReason::BlockedByPolicy;
 306→                let err_event = AgentEvent::RunErrored {
 307→                    run_id: input.run_id.clone(),
 308→                    session_id: input.session_id.clone(),
 309→                    error: err.to_string(),
 310→                };
 311→                event_handler(err_event.clone());
 312→                events.push(err_event);
 313→                break;
 314→            }
 315→
 316→            let model_turn = match provider.complete(&provider_request) {
 317→                Ok(turn) => turn,
 318→                Err(err) => {
 319→                    stop_reason = RunStopReason::Error;
 320→                    let err_event = AgentEvent::RunErrored {
 321→                        run_id: input.run_id.clone(),
 322→                        session_id: input.session_id.clone(),
 323→                        error: err.to_string(),
 324→                    };
 325→                    event_handler(err_event.clone());
 326→                    events.push(err_event);
 327→                    break;
 328→                }
 329→            };
 330→
 331→            if let Err(err) = self.run_after_model(&provider_request, &model_turn) {
 332→                stop_reason = RunStopReason::BlockedByPolicy;
 333→                let err_event = AgentEvent::RunErrored {
 334→                    run_id: input.run_id.clone(),
 335→                    session_id: input.session_id.clone(),
 336→                    error: err.to_string(),
 337→                };
 338→                event_handler(err_event.clone());
 339→                events.push(err_event);
 340→                break;
 341→            }
 342→
 343→            // Accumulate token usage if reported
 344→            if let Some(ref usage) = model_turn.usage {
 345→                total_usage.accumulate(usage);
 346→            }
 347→
 348→            let output_event = AgentEvent::ModelOutput {
 349→                run_id: input.run_id.clone(),
 350→                session_id: input.session_id.clone(),
 351→                iteration,
 352→                stop_reason: model_turn.stop_reason,
 353→                directive_count: model_turn.directives.len(),
 354→                usage: model_turn.usage,
 355→            };
 356→            event_handler(output_event.clone());
 357→            events.push(output_event);
 358→
 359→            let mut requested_tool = false;
 360→
 361→            for directive in model_turn.directives {
 362→                match directive {
 363→                    ModelDirective::Text { delta } => {
 364→                        let delta_event = AgentEvent::TextDelta {
 365→                            run_id: input.run_id.clone(),
 366→                            session_id: input.session_id.clone(),
 367→                            iteration,
 368→                            delta: delta.clone(),
 369→                        };
 370→                        event_handler(delta_event.clone());
 371→                        events.push(delta_event);
 372→                        messages.push(ChatMessage::assistant(delta));
 373→                    }
 374→                    ModelDirective::ToolCall { call } => {
 375→                        requested_tool = true;
 376→                        let tc_event = AgentEvent::ToolCallRequested {
 377→                            run_id: input.run_id.clone(),
 378→                            session_id: input.session_id.clone(),
 379→                            iteration,
 380→                            call: call.clone(),
 381→                        };
 382→                        event_handler(tc_event.clone());
 383→                        events.push(tc_event);
 384→
 385→                        let context = ToolContext {
 386→                            run_id: input.run_id.clone(),
 387→                            session_id: input.session_id.clone(),
 388→                            iteration,
 389→                        };
 390→
 391→                        if let Err(err) = self.run_pre_tool(&context, &call) {
 392→                            stop_reason = RunStopReason::BlockedByPolicy;
 393→                            let err_event = AgentEvent::ToolCallFailed {
 394→                                run_id: input.run_id.clone(),
 395→                                session_id: input.session_id.clone(),
 396→                                iteration,
 397→                                call_id: call.call_id.clone(),
 398→                                tool_name: call.tool_name.clone(),
 399→                                error: err.to_string(),
 400→                            };
 401→                            event_handler(err_event.clone());
 402→                            events.push(err_event);
 403→                            break;
 404→                        }
 405→
 406→                        let Some(tool) = self.tools.get(&call.tool_name) else {
 407→                            stop_reason = RunStopReason::Error;
 408→                            let err_event = AgentEvent::ToolCallFailed {
 409→                                run_id: input.run_id.clone(),
 410→                                session_id: input.session_id.clone(),
 411→                                iteration,
 412→                                call_id: call.call_id.clone(),
 413→                                tool_name: call.tool_name.clone(),
 414→                                error: format!(
 415→                                    "{}",
 416→                                    CoreError::ToolNotFound {
 417→                                        tool_name: call.tool_name.clone(),
 418→                                    }
 419→                                ),
 420→                            };
 421→                            event_handler(err_event.clone());
 422→                            events.push(err_event);
 423→                            break;
 424→                        };
 425→
 426→                        match tool.execute(&call, &context) {
 427→                            Ok(result) => {
 428→                                if let Some(patch) = &result.state_patch {
 429→                                    match state.apply_patch(patch) {
 430→                                        Ok(()) => {
 431→                                            let patch_event = AgentEvent::StatePatched {
 432→                                                run_id: input.run_id.clone(),
 433→                                                session_id: input.session_id.clone(),
 434→                                                iteration,
 435→                                                patch: patch.clone(),
 436→                                                revision: state.revision,
 437→                                            };
 438→                                            event_handler(patch_event.clone());
 439→                                            events.push(patch_event);
 440→                                        }
 441→                                        Err(err) => {
 442→                                            stop_reason = RunStopReason::Error;
 443→                                            let err_event = AgentEvent::ToolCallFailed {
 444→                                                run_id: input.run_id.clone(),
 445→                                                session_id: input.session_id.clone(),
 446→                                                iteration,
 447→                                                call_id: call.call_id.clone(),
 448→                                                tool_name: call.tool_name.clone(),
 449→                                                error: err.to_string(),
 450→                                            };
 451→                                            event_handler(err_event.clone());
 452→                                            events.push(err_event);
 453→                                            break;
 454→                                        }
 455→                                    }
 456→                                }
 457→
 458→                                if let Err(err) = self.run_post_tool(&context, &result) {
 459→                                    stop_reason = RunStopReason::BlockedByPolicy;
 460→                                    let err_event = AgentEvent::ToolCallFailed {
 461→                                        run_id: input.run_id.clone(),
 462→                                        session_id: input.session_id.clone(),
 463→                                        iteration,
 464→                                        call_id: call.call_id.clone(),
 465→                                        tool_name: call.tool_name.clone(),
 466→                                        error: err.to_string(),
 467→                                    };
 468→                                    event_handler(err_event.clone());
 469→                                    events.push(err_event);
 470→                                    break;
 471→                                }
 472→
 473→                                let completed_event = AgentEvent::ToolCallCompleted {
 474→                                    run_id: input.run_id.clone(),
 475→                                    session_id: input.session_id.clone(),
 476→                                    iteration,
 477→                                    result: ToolResultSummary::from(&result),
 478→                                };
 479→                                event_handler(completed_event.clone());
 480→                                events.push(completed_event);
 481→
 482→                                messages.push(ChatMessage::tool_result(
 483→                                    &result.call_id,
 484→                                    serde_json::to_string(&result.output)
 485→                                        .unwrap_or_else(|_| "{}".to_string()),
 486→                                ));
 487→                            }
 488→                            Err(err) => {
 489→                                stop_reason = RunStopReason::Error;
 490→                                let err_event = AgentEvent::ToolCallFailed {
 491→                                    run_id: input.run_id.clone(),
 492→                                    session_id: input.session_id.clone(),
 493→                                    iteration,
 494→                                    call_id: call.call_id.clone(),
 495→                                    tool_name: call.tool_name.clone(),
 496→                                    error: err.to_string(),
 497→                                };
 498→                                event_handler(err_event.clone());
 499→                                events.push(err_event);
 500→                                break;
 501→                            }
 502→                        }
 503→                    }
 504→                    ModelDirective::StatePatch { patch } => match state.apply_patch(&patch) {
 505→                        Ok(()) => {
 506→                            let patch_event = AgentEvent::StatePatched {
 507→                                run_id: input.run_id.clone(),
 508→                                session_id: input.session_id.clone(),
 509→                                iteration,
 510→                                patch: patch.clone(),
 511→                                revision: state.revision,
 512→                            };
 513→                            event_handler(patch_event.clone());
 514→                            events.push(patch_event);
 515→                        }
 516→                        Err(err) => {
 517→                            stop_reason = RunStopReason::Error;
 518→                            let err_event = AgentEvent::RunErrored {
 519→                                run_id: input.run_id.clone(),
 520→                                session_id: input.session_id.clone(),
 521→                                error: err.to_string(),
 522→                            };
 523→                            event_handler(err_event.clone());
 524→                            events.push(err_event);
 525→                            break;
 526→                        }
 527→                    },
 528→                    ModelDirective::FinalAnswer { text } => {
 529→                        final_answer = Some(text.clone());
 530→                        let delta_event = AgentEvent::TextDelta {
 531→                            run_id: input.run_id.clone(),
 532→                            session_id: input.session_id.clone(),
 533→                            iteration,
 534→                            delta: text.clone(),
 535→                        };
 536→                        event_handler(delta_event.clone());
 537→                        events.push(delta_event);
 538→                        messages.push(ChatMessage::assistant(text));
 539→                    }
 540→                }
 541→            }
 542→
 543→            if matches!(
 544→                stop_reason,
 545→                RunStopReason::Error | RunStopReason::BlockedByPolicy | RunStopReason::Cancelled
 546→            ) {
 547→                break;
 548→            }
 549→
 550→            match model_turn.stop_reason {
 551→                ModelStopReason::EndTurn => {
 552→                    stop_reason = RunStopReason::Completed;
 553→                    break;
 554→                }
 555→                ModelStopReason::NeedsUser => {
 556→                    stop_reason = RunStopReason::NeedsUser;
 557→                    break;
 558→                }
 559→                ModelStopReason::Safety => {
 560→                    stop_reason = RunStopReason::BlockedByPolicy;
 561→                    break;
 562→                }
 563→                ModelStopReason::ToolUse => {
 564→                    if !requested_tool {
 565→                        stop_reason = RunStopReason::Error;
 566→                        let err_event = AgentEvent::RunErrored {
 567→                            run_id: input.run_id.clone(),
 568→                            session_id: input.session_id.clone(),
 569→                            error: "model requested tool_use stop reason without tool call"
 570→                                .to_string(),
 571→                        };
 572→                        event_handler(err_event.clone());
 573→                        events.push(err_event);
 574→                        break;
 575→                    }
 576→                }
 577→                ModelStopReason::MaxTokens | ModelStopReason::Unknown => {
 578→                    if !requested_tool {
 579→                        stop_reason = RunStopReason::Error;
 580→                        let err_event = AgentEvent::RunErrored {
 581→                            run_id: input.run_id.clone(),
 582→                            session_id: input.session_id.clone(),
 583→                            error: "model returned non-terminal stop reason without tool call"
 584→                                .to_string(),
 585→                        };
 586→                        event_handler(err_event.clone());
 587→                        events.push(err_event);
 588→                        break;
 589→                    }
 590→                }
 591→            }
 592→        }
 593→
 594→        if total_iterations == self.config.max_iterations
 595→            && stop_reason == RunStopReason::BudgetExceeded
 596→        {
 597→            let err_event = AgentEvent::RunErrored {
 598→                run_id: input.run_id.clone(),
 599→                session_id: input.session_id.clone(),
 600→                error: "max iteration budget exceeded".to_string(),
 601→            };
 602→            event_handler(err_event.clone());
 603→            events.push(err_event);
 604→        }
 605→
 606→        let finished_event = AgentEvent::RunFinished {
 607→            run_id: input.run_id.clone(),
 608→            session_id: input.session_id.clone(),
 609→            reason: stop_reason,
 610→            total_iterations,
 611→            final_answer: final_answer.clone(),
 612→        };
 613→        event_handler(finished_event.clone());
 614→        events.push(finished_event);
 615→
 616→        let output = RunOutput {
 617→            run_id: input.run_id,
 618→            session_id: input.session_id,
 619→            branch_id: input.branch_id,
 620→            events,
 621→            messages,
 622→            state,
 623→            reason: stop_reason,
 624→            final_answer,
 625→            total_usage,
 626→        };
 627→
 628→        let _ = self
 629→            .middlewares
 630→            .iter()
 631→            .try_for_each(|middleware| middleware.on_run_finished(&output));
 632→
 633→        output
 634→    }
