  1→//! Sandbox policy and command execution.
  2→//!
  3→//! Provides the `SandboxPolicy` configuration and `CommandRunner` trait
  4→//! for executing commands within policy constraints.
  5→
  6→use crate::error::{PraxisError, PraxisResult};
  7→use aios_protocol::sandbox::NetworkPolicy;
  8→use serde::{Deserialize, Serialize};
  9→use std::collections::BTreeSet;
 10→use std::path::PathBuf;
 11→use tracing::{debug, warn};
 12→
 13→/// Security policy for sandboxed command execution.
 14→#[derive(Debug, Clone, Serialize, Deserialize)]
 15→pub struct SandboxPolicy {
 16→    /// Filesystem root that all operations are confined to.
 17→    pub workspace_root: PathBuf,
 18→    /// Whether shell execution is enabled.
 19→    #[serde(default = "default_true")]
 20→    pub shell_enabled: bool,
 21→    /// Network access policy.
 22→    #[serde(default)]
 23→    pub network: NetworkPolicy,
 24→    /// Environment variables allowed to pass through.
 25→    #[serde(default)]
 26→    pub allowed_env: BTreeSet<String>,
 27→    /// Maximum execution time in milliseconds.
 28→    #[serde(default = "default_max_execution_ms")]
 29→    pub max_execution_ms: u64,
 30→    /// Maximum stdout size in bytes.
 31→    #[serde(default = "default_max_output_bytes")]
 32→    pub max_stdout_bytes: usize,
 33→    /// Maximum stderr size in bytes.
 34→    #[serde(default = "default_max_output_bytes")]
 35→    pub max_stderr_bytes: usize,
 36→}
 37→
 38→fn default_true() -> bool {
 39→    true
 40→}
 41→
 42→fn default_max_execution_ms() -> u64 {
 43→    60_000
 44→}
