245→// ── GlobTool ─────────────────────────────────────────────────────────
246→
247→/// Searches for files matching a glob pattern within the workspace.
248→pub struct GlobTool {
249→    policy: FsPolicy,
250→}
251→
252→impl GlobTool {
253→    pub fn new(policy: FsPolicy) -> Self {
254→        Self { policy }
255→    }
256→}
257→
258→impl Tool for GlobTool {
259→    fn definition(&self) -> ToolDefinition {
260→        ToolDefinition {
261→            name: "glob".into(),
262→            description: "Search for files matching a glob pattern within the workspace.".into(),
263→            input_schema: json!({
264→                "type": "object",
265→                "properties": {
266→                    "pattern": { "type": "string", "description": "Glob pattern (e.g. **/*.rs)" },
267→                    "path": { "type": "string", "description": "Base directory (optional, defaults to workspace root)" }
268→                },
269→                "required": ["pattern"]
270→            }),
271→            title: Some("Glob Search".into()),
272→            output_schema: None,
273→            annotations: Some(ToolAnnotations {
274→                read_only: true,
275→                idempotent: true,
276→                ..Default::default()
277→            }),
278→            category: Some("filesystem".into()),
279→            tags: vec!["fs".into(), "search".into()],
280→            timeout_secs: Some(30),
281→        }
282→    }
283→
284→    fn execute(&self, call: &ToolCall, _ctx: &ToolContext) -> Result<ToolResult, ToolError> {
285→        let pattern = call
286→            .input
287→            .get("pattern")
288→            .and_then(|v| v.as_str())
289→            .ok_or_else(|| ToolError::InvalidInput {
290→                message: "Missing or invalid 'pattern' argument".into(),
291→            })?;
292→
293→        let base_dir = call
294→            .input
295→            .get("path")
296→            .and_then(|v| v.as_str())
297→            .map(PathBuf::from)
298→            .unwrap_or_else(|| self.policy.workspace_root().to_path_buf());
299→
300→        let base_dir = self
301→            .policy
302→            .resolve_existing(Path::new(&base_dir))
303→            .map_err(|e| ToolError::ExecutionFailed {
304→                tool_name: "glob".into(),
305→                message: e.to_string(),
306→            })?;
307→
308→        let full_pattern = base_dir.join(pattern).display().to_string();
309→
310→        let matches: Vec<String> = glob::glob(&full_pattern)
311→            .map_err(|e| ToolError::ExecutionFailed {
312→                tool_name: "glob".into(),
313→                message: format!("Invalid glob pattern: {e}"),
314→            })?
315→            .filter_map(Result::ok)
316→            .filter(|path| self.policy.resolve_existing(path).is_ok())
317→            .map(|path| {
318→                path.strip_prefix(self.policy.workspace_root())
319→                    .map(|p| p.display().to_string())
320→                    .unwrap_or_else(|_| path.display().to_string())
321→            })
322→            .collect();
323→
324→        let count = matches.len();
325→
326→        Ok(ToolResult {
327→            call_id: call.call_id.clone(),
328→            tool_name: call.tool_name.clone(),
329→            output: json!({ "matches": matches, "count": count }),
330→            content: None,
331→            is_error: false,
332→        })
333→    }
334→}
