  1→//! Hashline editing with Blake3 content-addressed line tags.
  2→//!
  3→//! Files are read with line numbers and content hashes. Edits must
  4→//! reference these tags, ensuring the agent edits the version it "sees".
  5→
  6→use aios_protocol::tool::{
  7→    Tool, ToolAnnotations, ToolCall, ToolContext, ToolDefinition, ToolError, ToolResult,
  8→};
  9→use blake3::Hasher;
 10→use praxis_core::workspace::FsPolicy;
 11→use serde::{Deserialize, Serialize};
 12→use serde_json::json;
 13→use std::path::Path;
 14→use thiserror::Error;
 15→
 16→/// A line of content with its hash tag.
 17→#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Eq)]
 18→pub struct HashedLine {
 19→    pub line_no: usize,
 20→    pub tag: String,
 21→    pub text: String,
 22→}
 23→
 24→/// An edit operation referencing a line by its hash tag.
 25→#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Eq)]
 26→#[serde(tag = "op", rename_all = "snake_case")]
 27→pub enum TaggedEditOp {
 28→    ReplaceLine { tag: String, new_text: String },
 29→    InsertAfterTag { tag: String, new_text: String },
 30→    DeleteLine { tag: String },
 31→}
 32→
 33→#[derive(Debug, Clone)]
 34→struct EditableLine {
 35→    anchor_tag: Option<String>,
 36→    text: String,
 37→}
 38→
 39→/// Compute hash tags for all lines in content.
 40→pub fn hash_lines(content: &str) -> Vec<HashedLine> {
 41→    content
 42→        .lines()
 43→        .enumerate()
 44→        .map(|(idx, line)| HashedLine {
 45→            line_no: idx + 1,
 46→            tag: line_tag(idx + 1, line),
 47→            text: line.to_string(),
 48→        })
 49→        .collect()
 50→}
 51→
 52→/// Render content with line numbers and hash tags for display.
 53→pub fn render_hashed_content(content: &str) -> String {
 54→    hash_lines(content)
 55→        .into_iter()
 56→        .map(|line| format!("{:>4} {} | {}", line.line_no, line.tag, line.text))
 57→        .collect::<Vec<_>>()
 58→        .join("\n")
 59→}
 60→
 61→/// Apply a sequence of tagged edit operations to content.
 62→pub fn apply_tagged_edits(content: &str, ops: &[TaggedEditOp]) -> Result<String, EditError> {
 63→    let initial_lines = hash_lines(content);
 64→
 65→    if initial_lines.is_empty() && !ops.is_empty() {
 66→        return Err(EditError::EmptyContent);
 67→    }
 68→
 69→    let mut editable: Vec<EditableLine> = initial_lines
 70→        .iter()
 71→        .map(|line| EditableLine {
 72→            anchor_tag: Some(line.tag.clone()),
 73→            text: line.text.clone(),
 74→        })
 75→        .collect();
 76→
 77→    for op in ops {
 78→        match op {
 79→            TaggedEditOp::ReplaceLine { tag, new_text } => {
 80→                let idx = find_anchor_index(&editable, tag)?;
 81→                editable[idx].text = new_text.clone();
 82→            }
 83→            TaggedEditOp::InsertAfterTag { tag, new_text } => {
 84→                let idx = find_anchor_index(&editable, tag)?;
 85→                editable.insert(
 86→                    idx + 1,
 87→                    EditableLine {
 88→                        anchor_tag: None,
 89→                        text: new_text.clone(),
 90→                    },
 91→                );
 92→            }
 93→            TaggedEditOp::DeleteLine { tag } => {
 94→                let idx = find_anchor_index(&editable, tag)?;
 95→                editable.remove(idx);
 96→            }
 97→        }
 98→    }
 99→
100→    Ok(editable
101→        .into_iter()
102→        .map(|line| line.text)
103→        .collect::<Vec<_>>()
104→        .join("\n"))
105→}
106→
107→fn find_anchor_index(lines: &[EditableLine], tag: &str) -> Result<usize, EditError> {
108→    lines
109→        .iter()
110→        .position(|line| line.anchor_tag.as_deref() == Some(tag))
111→        .ok_or_else(|| EditError::StaleTag(tag.to_string()))
112→}
113→
114→fn line_tag(line_no: usize, text: &str) -> String {
115→    let mut hasher = Hasher::new();
116→    hasher.update(line_no.to_string().as_bytes());
117→    hasher.update(b":");
118→    hasher.update(text.as_bytes());
119→    let digest = hasher.finalize().to_hex().to_string();
120→    digest.chars().take(8).collect()
121→}
122→
123→/// Errors from the hashline editing system.
124→#[derive(Debug, Error)]
125→pub enum EditError {
126→    #[error("input content is empty; tags are required before edit")]
127→    EmptyContent,
128→    #[error("tag is stale or missing in current content: {0}")]
129→    StaleTag(String),
130→}
131→
132→// ── EditFileTool ──────────────────────────────────────────────────────
133→
134→/// Tool that applies hashline edits to files.
135→pub struct EditFileTool {
136→    policy: FsPolicy,
137→}
138→
139→impl EditFileTool {
140→    pub fn new(policy: FsPolicy) -> Self {
141→        Self { policy }
142→    }
143→}
144→
145→impl Tool for EditFileTool {
146→    fn definition(&self) -> ToolDefinition {
147→        ToolDefinition {
148→            name: "edit_file".into(),
149→            description: "Edits a file using line tags. Operations: replace_line, insert_after_tag, delete_line.".into(),
150→            input_schema: json!({
151→                "type": "object",
152→                "properties": {
153→                    "path": { "type": "string", "description": "Path to the file" },
154→                    "ops": {
155→                        "type": "array",
156→                        "items": {
157→                            "type": "object",
158→                            "oneOf": [
159→                                { "properties": { "op": { "const": "replace_line" }, "tag": { "type": "string" }, "new_text": { "type": "string" } }, "required": ["op", "tag", "new_text"] },
160→                                { "properties": { "op": { "const": "insert_after_tag" }, "tag": { "type": "string" }, "new_text": { "type": "string" } }, "required": ["op", "tag", "new_text"] },
161→                                { "properties": { "op": { "const": "delete_line" }, "tag": { "type": "string" } }, "required": ["op", "tag"] }
162→                            ]
163→                        }
164→                    }
165→                },
166→                "required": ["path", "ops"]
167→            }),
168→            title: Some("Edit File".into()),
169→            output_schema: None,
170→            annotations: Some(ToolAnnotations {
171→                destructive: true,
172→                ..Default::default()
173→            }),
174→            category: Some("filesystem".into()),
175→            tags: vec!["fs".into(), "edit".into()],
176→            timeout_secs: Some(30),
177→        }
178→    }
179→
180→    fn execute(&self, call: &ToolCall, _ctx: &ToolContext) -> Result<ToolResult, ToolError> {
181→        let path_str = call
182→            .input
183→            .get("path")
184→            .and_then(|v| v.as_str())
185→            .ok_or_else(|| ToolError::InvalidInput {
186→                message: "Missing or invalid 'path' argument".into(),
187→            })?;
188→
189→        let ops_value = call
190→            .input
191→            .get("ops")
192→            .ok_or_else(|| ToolError::InvalidInput {
193→                message: "Missing 'ops' argument".into(),
194→            })?;
195→
196→        let ops: Vec<TaggedEditOp> =
197→            serde_json::from_value(ops_value.clone()).map_err(|e| ToolError::InvalidInput {
198→                message: format!("Invalid 'ops' format: {e}"),
199→            })?;
200→
201→        let path = self
202→            .policy
203→            .resolve_for_write(Path::new(path_str))
204→            .map_err(|e| ToolError::PolicyViolation {
205→                message: e.to_string(),
206→            })?;
207→
208→        let content = std::fs::read_to_string(&path).map_err(|e| ToolError::ExecutionFailed {
209→            tool_name: "edit_file".into(),
210→            message: format!("Failed to read file: {e}"),
211→        })?;
212→
213→        let new_content =
214→            apply_tagged_edits(&content, &ops).map_err(|e| ToolError::ExecutionFailed {
215→                tool_name: "edit_file".into(),
216→                message: format!("Edit failed: {e}"),
217→            })?;
218→
219→        std::fs::write(&path, &new_content).map_err(|e| ToolError::ExecutionFailed {
220→            tool_name: "edit_file".into(),
221→            message: format!("Failed to write file: {e}"),
222→        })?;
223→
224→        let hashed_content = render_hashed_content(&new_content);
225→
226→        Ok(ToolResult {
227→            call_id: call.call_id.clone(),
228→            tool_name: call.tool_name.clone(),
229→            output: json!({ "success": true, "content": hashed_content, "path": path }),
230→            content: None,
231→            is_error: false,
232→        })
233→    }
234→}
