  1→//! Skill registry for discovery and lookup.
  2→//!
  3→//! Scans directories for SKILL.md files, caches metadata,
  4→//! and provides on-demand activation.
  5→
  6→use crate::parser::{SkillMetadata, SkillParseError, parse_skill_md};
  7→use std::collections::BTreeMap;
  8→use std::path::{Path, PathBuf};
  9→use thiserror::Error;
 10→
 11→/// A loaded skill with its full content.
 12→#[derive(Debug, Clone)]
 13→pub struct LoadedSkill {
 14→    pub meta: SkillMetadata,
 15→    /// Markdown instructions (body after frontmatter).
 16→    pub body: String,
 17→    /// Skill directory (for relative file refs).
 18→    pub root_dir: PathBuf,
 19→}
 20→
 21→/// Skill registry: scans directories, caches metadata, loads on demand.
 22→pub struct SkillRegistry {
 23→    skills: BTreeMap<String, LoadedSkill>,
 24→}
 25→
 26→impl SkillRegistry {
 27→    /// Scan directories for SKILL.md files. Returns a registry of discovered skills.
 28→    pub fn discover(dirs: &[PathBuf]) -> Result<Self, SkillError> {
 29→        let mut skills = BTreeMap::new();
 30→
 31→        for dir in dirs {
 32→            if !dir.exists() {
 33→                continue;
 34→            }
 35→
 36→            for entry in walkdir::WalkDir::new(dir)
 37→                .into_iter()
 38→                .filter_map(Result::ok)
 39→                .filter(|e| e.file_type().is_file())
 40→                .filter(|e| {
 41→                    e.file_name()
 42→                        .to_string_lossy()
 43→                        .eq_ignore_ascii_case("SKILL.md")
 44→                })
 45→            {
 46→                let path = entry.path();
 47→                let content = std::fs::read_to_string(path).map_err(|e| SkillError::Io {
 48→                    path: path.to_path_buf(),
 49→                    source: e,
 50→                })?;
 51→
 52→                match parse_skill_md(&content) {
 53→                    Ok((meta, body)) => {
 54→                        let root_dir = path
 55→                            .parent()
 56→                            .unwrap_or_else(|| Path::new("."))
 57→                            .to_path_buf();
 58→
 59→                        let name = meta.name.clone();
 60→                        skills.insert(
 61→                            name,
 62→                            LoadedSkill {
 63→                                meta,
 64→                                body,
 65→                                root_dir,
 66→                            },
 67→                        );
 68→                    }
 69→                    Err(e) => {
 70→                        tracing::warn!(
 71→                            path = %path.display(),
 72→                            error = %e,
 73→                            "Skipping malformed skill"
 74→                        );
 75→                    }
 76→                }
 77→            }
 78→        }
 79→
 80→        Ok(Self { skills })
 81→    }
 82→
 83→    /// Number of discovered skills.
 84→    pub fn count(&self) -> usize {
 85→        self.skills.len()
 86→    }
 87→
 88→    /// Get skill metadata for system prompt injection.
 89→    pub fn system_prompt_catalog(&self) -> String {
 90→        if self.skills.is_empty() {
 91→            return String::new();
 92→        }
 93→
 94→        let mut lines = vec!["Available skills:".to_string()];
 95→        for skill in self.skills.values() {
 96→            let invocable = if skill.meta.user_invocable == Some(true) {
 97→                " [user-invocable]"
 98→            } else {
 99→                ""
100→            };
101→            lines.push(format!(
102→                "- {}: {}{}",
103→                skill.meta.name, skill.meta.description, invocable
104→            ));
105→        }
106→        lines.join("\n")
107→    }
108→
109→    /// Load full skill content when activated.
110→    pub fn activate(&self, name: &str) -> Option<&LoadedSkill> {
111→        self.skills.get(name)
112→    }
113→
114→    /// Get all skill names.
115→    pub fn skill_names(&self) -> Vec<String> {
116→        self.skills.keys().cloned().collect()
117→    }
118→
119→    /// Get allowed tools for an active skill (if restricted).
120→    pub fn allowed_tools(&self, name: &str) -> Option<&[String]> {
121→        self.skills
122→            .get(name)
123→            .and_then(|s| s.meta.allowed_tools.as_deref())
124→    }
125→}
126→
127→/// Errors from the skill system.
128→#[derive(Debug, Error)]
129→pub enum SkillError {
130→    #[error("IO error reading {path}: {source}")]
131→    Io {
132→        path: PathBuf,
133→        #[source]
134→        source: std::io::Error,
135→    },
136→    #[error("skill parse error: {0}")]
137→    Parse(#[from] SkillParseError),
138→}
