  1→//! MCP server connection management.
  2→//!
  3→//! Handles connecting to MCP servers via stdio transport
  4→//! and discovering their available tools.
  5→
  6→use crate::tool::McpTool;
  7→use aios_protocol::tool::{ToolAnnotations, ToolDefinition};
  8→use rmcp::ServiceExt;
  9→use rmcp::model::Tool as McpToolDef;
 10→use rmcp::service::{Peer, RoleClient};
 11→use rmcp::transport::TokioChildProcess;
 12→use serde::{Deserialize, Serialize};
 13→use serde_json::Value;
 14→use std::sync::Arc;
 15→use thiserror::Error;
 16→use tokio::process::Command;
 17→use tokio::runtime::Handle;
 18→
 19→/// Configuration for connecting to an MCP server.
 20→#[derive(Debug, Clone, Serialize, Deserialize)]
 21→#[serde(deny_unknown_fields)]
 22→pub struct McpServerConfig {
 23→    pub name: String,
 24→    pub transport: McpTransport,
 25→}
 26→
 27→/// Transport configuration for MCP connections.
 28→#[derive(Debug, Clone, Serialize, Deserialize)]
 29→#[serde(tag = "type", rename_all = "snake_case")]
 30→pub enum McpTransport {
 31→    Stdio { command: String, args: Vec<String> },
 32→}
 33→
 34→/// A connected MCP client holding the running service.
 35→pub struct McpConnection {
 36→    pub server_name: String,
 37→    pub tools: Vec<McpTool>,
 38→    _service: Box<dyn std::any::Any + Send>,
 39→}
 40→
 41→/// Connect to an MCP server via stdio and return all its tools.
 42→pub async fn connect_mcp_stdio(config: &McpServerConfig) -> Result<McpConnection, McpError> {
 43→    let McpTransport::Stdio {
 44→        ref command,
 45→        ref args,
 46→    } = config.transport;
 47→
 48→    let mut cmd = Command::new(command);
 49→    cmd.args(args);
 50→
 51→    let transport = TokioChildProcess::new(cmd).map_err(|e| McpError::Connection(e.to_string()))?;
 52→
 53→    let service = ().serve(transport).await.map_err(|e| McpError::Initialize(e.to_string()))?;
 54→
 55→    let tools_result = service
 56→        .list_tools(None)
 57→        .await
 58→        .map_err(|e| McpError::ListTools(e.to_string()))?;
 59→
 60→    let runtime = Handle::current();
 61→    let peer: Arc<Peer<RoleClient>> = Arc::new(service.peer().clone());
 62→
 63→    let mcp_tools: Vec<McpTool> = tools_result
 64→        .tools
 65→        .iter()
 66→        .map(|mcp_tool| {
 67→            let (definition, mcp_tool_name) = mcp_tool_to_definition(&config.name, mcp_tool);
 68→            McpTool::new(definition, peer.clone(), mcp_tool_name, runtime.clone())
 69→        })
 70→        .collect();
 71→
 72→    Ok(McpConnection {
 73→        server_name: config.name.clone(),
 74→        tools: mcp_tools,
 75→        _service: Box::new(service),
 76→    })
 77→}
 78→
 79→/// Convert an MCP tool definition to a canonical ToolDefinition.
 80→pub fn mcp_tool_to_definition(
 81→    server_name: &str,
 82→    mcp_tool: &McpToolDef,
 83→) -> (ToolDefinition, String) {
 84→    let mcp_name = mcp_tool.name.to_string();
 85→    let canonical_name = format!("mcp_{}_{}", server_name, mcp_name);
 86→
 87→    let annotations = mcp_tool.annotations.as_ref().map(|ann| ToolAnnotations {
 88→        read_only: ann.read_only_hint.unwrap_or(false),
 89→        destructive: ann.destructive_hint.unwrap_or(true),
 90→        idempotent: ann.idempotent_hint.unwrap_or(false),
 91→        open_world: ann.open_world_hint.unwrap_or(true),
 92→        requires_confirmation: false,
 93→    });
 94→
 95→    let input_schema = Value::Object(mcp_tool.input_schema.as_ref().clone());
 96→
 97→    let output_schema = mcp_tool
 98→        .output_schema
 99→        .as_ref()
100→        .map(|s| Value::Object(s.as_ref().clone()));
101→
102→    let def = ToolDefinition {
103→        name: canonical_name,
104→        description: mcp_tool.description.as_deref().unwrap_or("").to_string(),
105→        input_schema,
106→        title: mcp_tool
107→            .title
108→            .clone()
109→            .or_else(|| mcp_tool.annotations.as_ref().and_then(|a| a.title.clone())),
110→        output_schema,
111→        annotations,
112→        category: Some("mcp".into()),
113→        tags: vec!["mcp".into(), server_name.into()],
114→        timeout_secs: Some(60),
115→    };
116→
117→    (def, mcp_name)
118→}
119→
120→/// Errors from MCP connection management.
121→#[derive(Debug, Error)]
122→pub enum McpError {
123→    #[error("MCP connection failed: {0}")]
124→    Connection(String),
125→    #[error("MCP initialization failed: {0}")]
126→    Initialize(String),
127→    #[error("MCP tools/list failed: {0}")]
128→    ListTools(String),
129→}
