 1→use aios_protocol::{
 2→    KernelError, ToolExecutionReport, ToolExecutionRequest, ToolHarnessPort, ToolOutcome, ToolRunId,
 3→};
 4→use arcan_core::protocol::ToolCall;
 5→use arcan_core::runtime::{ToolContext, ToolRegistry};
 6→use async_trait::async_trait;
 7→use std::sync::Arc;
 8→
 9→#[async_trait]
10→pub trait ToolHarnessObserver: Send + Sync {
11→    async fn post_execute(&self, session_id: String, tool_name: String);
12→}
13→
14→#[derive(Clone)]
15→pub struct ArcanHarnessAdapter {
16→    registry: ToolRegistry,
17→    observers: Vec<Arc<dyn ToolHarnessObserver>>,
18→}
19→
20→impl ArcanHarnessAdapter {
21→    pub fn new(registry: ToolRegistry) -> Self {
22→        Self {
23→            registry,
24→            observers: Vec::new(),
25→        }
26→    }
27→
28→    pub fn with_observer(mut self, observer: Arc<dyn ToolHarnessObserver>) -> Self {
29→        self.observers.push(observer);
30→        self
31→    }
32→}
33→
34→#[async_trait]
35→impl ToolHarnessPort for ArcanHarnessAdapter {
36→    async fn execute(
37→        &self,
38→        request: ToolExecutionRequest,
39→    ) -> Result<ToolExecutionReport, KernelError> {
40→        let tool = self
41→            .registry
42→            .get(&request.call.tool_name)
43→            .ok_or_else(|| KernelError::ToolNotFound(request.call.tool_name.clone()))?;
44→
45→        let arcan_call = ToolCall {
46→            call_id: request.call.call_id.clone(),
47→            tool_name: request.call.tool_name.clone(),
48→            input: request.call.input.clone(),
49→        };
50→        let context = ToolContext {
51→            run_id: format!("run-{}", request.call.call_id),
52→            session_id: request.session_id.as_str().to_owned(),
53→            iteration: 1,
54→        };
55→
56→        let result = tool
57→            .execute(&arcan_call, &context)
58→            .map_err(|error| KernelError::Runtime(error.to_string()))?;
59→        let exit_status = if result.is_error { 1 } else { 0 };
60→        let outcome = if result.is_error {
61→            ToolOutcome::Failure {
62→                error: result
63→                    .output
64→                    .get("error")
65→                    .and_then(|value| value.as_str())
66→                    .map(ToOwned::to_owned)
67→                    .unwrap_or_else(|| "tool execution failed".to_owned()),
68→            }
69→        } else {
70→            ToolOutcome::Success {
71→                output: result.output,
72→            }
73→        };
74→
75→        for observer in &self.observers {
76→            observer
77→                .as_ref()
78→                .post_execute(
79→                    request.session_id.as_str().to_owned(),
80→                    arcan_call.tool_name.clone(),
81→                )
82→                .await;
83→        }
84→
85→        Ok(ToolExecutionReport {
86→            tool_run_id: ToolRunId::default(),
87→            call_id: arcan_call.call_id,
88→            tool_name: arcan_call.tool_name,
89→            exit_status,
90→            duration_ms: 0,
91→            outcome,
92→        })
93→    }
94→}
