1002→    async fn record_tool_report(
1003→        &self,
1004→        session_id: &SessionId,
1005→        branch_id: &BranchId,
1006→        manifest: &SessionManifest,
1007→        report: &ToolExecutionReport,
1008→    ) -> Result<u64> {
1009→        let mut emitted = 0;
1010→
1011→        self.append_event(
1012→            session_id,
1013→            branch_id,
1014→            EventKind::ToolCallStarted {
1015→                tool_run_id: report.tool_run_id.clone(),
1016→                tool_name: report.tool_name.clone(),
1017→            },
1018→        )
1019→        .await?;
1020→        emitted += 1;
1021→
1022→        let status = if report.exit_status == 0 {
1023→            SpanStatus::Ok
1024→        } else {
1025→            SpanStatus::Error
1026→        };
1027→        let result_value = serde_json::to_value(&report.outcome).unwrap_or_default();
1028→
1029→        self.append_event(
1030→            session_id,
1031→            branch_id,
1032→            EventKind::ToolCallCompleted {
1033→                tool_run_id: report.tool_run_id.clone(),
1034→                call_id: None,
1035→                tool_name: report.tool_name.clone(),
1036→                result: result_value,
1037→                duration_ms: 0,
1038→                status,
1039→            },
1040→        )
1041→        .await?;
1042→        emitted += 1;
1043→
1044→        if let ToolOutcome::Success { output } = &report.outcome
1045→            && let Some(path) = output.get("path").and_then(|v| v.as_str())
1046→        {
1047→            let full_path =
1048→                PathBuf::from(&manifest.workspace_root).join(path.trim_start_matches('/'));
1049→            let content_hash = if fs::try_exists(&full_path).await.unwrap_or(false) {
1050→                let data = fs::read(&full_path).await?;
1051→                sha256_bytes(&data)
1052→            } else {
1053→                "deleted".to_owned()
1054→            };
1055→
1056→            self.append_event(
1057→                session_id,
1058→                branch_id,
1059→                EventKind::FileMutated {
1060→                    path: path.to_owned(),
1061→                    content_hash,
1062→                },
1063→            )
1064→            .await?;
1065→            emitted += 1;
1066→        }
1067→
1068→        let run_dir = PathBuf::from(&manifest.workspace_root)
1069→            .join("tools")
1070→            .join("runs")
1071→            .join(report.tool_run_id.as_str());
1072→
1073→        fs::create_dir_all(&run_dir).await?;
1074→        self.write_pretty_json(run_dir.join("report.json"), report)
1075→            .await?;
1076→
1077→        let observation = extract_observation(&EventRecord::new(
1078→            session_id.clone(),
1079→            branch_id.clone(),
1080→            self.peek_last_sequence(session_id, branch_id)?,
1081→            EventKind::ToolCallCompleted {
1082→                tool_run_id: report.tool_run_id.clone(),
1083→                call_id: None,
1084→                tool_name: report.tool_name.clone(),
1085→                result: serde_json::to_value(&report.outcome).unwrap_or_default(),
1086→                duration_ms: 0,
1087→                status,
1088→            },
1089→        ));
1090→
1091→        if let Some(observation) = observation {
1092→            self.append_event(
1093→                session_id,
1094→                branch_id,
1095→                EventKind::Custom {
1096→                    event_type: "ObservationExtracted".to_owned(),
1097→                    data: serde_json::json!({
1098→                        "observation_id": observation.observation_id.to_string(),
1099→                    }),
1100→                },
1101→            )
1102→            .await?;
1103→            emitted += 1;
1104→        }
1105→
1106→        Ok(emitted)
1107→    }
