1166→    fn next_sequence(&self, session_id: &SessionId, branch_id: &BranchId) -> Result<u64> {
1167→        let mut sessions = self.sessions.lock();
1168→        let session = sessions
1169→            .get_mut(session_id.as_str())
1170→            .with_context(|| format!("session not found: {session_id}"))?;
1171→        if !session.branches.contains_key(branch_id) {
1172→            bail!("branch not found: {}", branch_id.as_str());
1173→        }
1174→        if let Some(merged_into) = session
1175→            .branches
1176→            .get(branch_id)
1177→            .and_then(|branch| branch.merged_into.as_ref())
1178→        {
1179→            bail!(
1180→                "branch {} is merged into {} and is read-only",
1181→                branch_id.as_str(),
1182→                merged_into.as_str()
1183→            );
1184→        }
1185→        let sequence = *session
1186→            .next_sequence_by_branch
1187→            .entry(branch_id.clone())
1188→            .or_insert(1);
1189→        session
1190→            .next_sequence_by_branch
1191→            .insert(branch_id.clone(), sequence.saturating_add(1));
1192→        Ok(sequence)
1193→    }
1194→
1195→    fn peek_last_sequence(&self, session_id: &SessionId, branch_id: &BranchId) -> Result<u64> {
1196→        let sessions = self.sessions.lock();
1197→        let session = sessions
1198→            .get(session_id.as_str())
1199→            .with_context(|| format!("session not found: {session_id}"))?;
1200→        if !session.branches.contains_key(branch_id) {
1201→            bail!("branch not found: {}", branch_id.as_str());
1202→        }
1203→        Ok(session
1204→            .next_sequence_by_branch
1205→            .get(branch_id)
1206→            .copied()
1207→            .unwrap_or(1)
1208→            .saturating_sub(1))
1209→    }
1210→
1211→    async fn resync_next_sequence(
1212→        &self,
1213→        session_id: &SessionId,
1214→        branch_id: &BranchId,
1215→    ) -> Result<()> {
1216→        let latest = self
1217→            .event_store
1218→            .head(session_id.clone(), branch_id.clone())
1219→            .await
1220→            .map_err(|error| anyhow::anyhow!(error.to_string()))
1221→            .context("failed loading latest sequence for resync")?;
1222→        let mut sessions = self.sessions.lock();
1223→        let session = sessions
1224→            .get_mut(session_id.as_str())
1225→            .with_context(|| format!("session not found: {session_id}"))?;
1226→        if !session.branches.contains_key(branch_id) {
1227→            bail!("branch not found: {}", branch_id.as_str());
1228→        }
1229→        session
1230→            .next_sequence_by_branch
1231→            .insert(branch_id.clone(), latest.saturating_add(1));
1232→        Ok(())
1233→    }
