1466→fn extract_observation(event: &EventRecord) -> Option<aios_protocol::Observation> {
1467→    let text = match &event.kind {
1468→        EventKind::ToolCallCompleted {
1469→            tool_name,
1470→            result,
1471→            status,
1472→            ..
1473→        } => format!("tool call completed ({tool_name}): {result} [status={status:?}]"),
1474→        EventKind::ErrorRaised { message } => format!("error observed: {message}"),
1475→        EventKind::CheckpointCreated { checkpoint_id, .. } => {
1476→            format!("checkpoint created: {checkpoint_id}")
1477→        }
1478→        _ => return None,
1479→    };
1480→
1481→    Some(aios_protocol::Observation {
1482→        observation_id: uuid::Uuid::new_v4(),
1483→        created_at: event.timestamp,
1484→        text,
1485→        tags: vec!["auto".to_owned()],
1486→        provenance: aios_protocol::Provenance {
1487→            event_start: event.sequence,
1488→            event_end: event.sequence,
1489→            files: vec![FileProvenance {
1490→                path: format!(
1491→                    "events/{}.jsonl#branch={}",
1492→                    event.session_id.as_str(),
1493→                    event.branch_id.as_str()
1494→                ),
1495→                sha256: "pending".to_owned(),
1496→            }],
1497→        },
1498→    })
1499→}
