 80→#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
 81→#[serde(tag = "op", rename_all = "snake_case")]
 82→pub enum PatchOp {
 83→    Set {
 84→        path: String,
 85→        value: Value,
 86→    },
 87→    Merge {
 88→        path: String,
 89→        object: Value,
 90→    },
 91→    Append {
 92→        path: String,
 93→        values: Vec<Value>,
 94→    },
 95→    Tombstone {
 96→        path: String,
 97→        reason: String,
 98→        #[serde(default, skip_serializing_if = "Option::is_none")]
 99→        replaced_by: Option<String>,
100→    },
101→    SetRef {
102→        path: String,
103→        blob_ref: BlobRef,
104→    },
105→}
