fn apply_homeostasis_controllers(
    &self,
    state: &mut AgentStateVector,
    report: &ToolExecutionReport,
) {
    // Decrement budget regardless of outcome
    state.budget.tool_calls_remaining = 
        state.budget.tool_calls_remaining.saturating_sub(1);
    state.budget.tokens_remaining = 
        state.budget.tokens_remaining.saturating_sub(750);
    state.budget.time_remaining_ms = 
        state.budget.time_remaining_ms.saturating_sub(1200);

    if report.exit_status == 0 {
        // SUCCESS CASE:
        state.progress = (state.progress + 0.12).min(1.0);           // +12% progress
        state.uncertainty = (state.uncertainty * 0.85).max(0.05);    // -15% uncertainty (multiply by 0.85)
        state.error_streak = 0;                                      // reset error counter
        state.side_effect_pressure = 
            (state.side_effect_pressure + 0.2).min(1.0);             // +20% side effect pressure
    } else {
        // FAILURE CASE:
        state.error_streak += 1;
        state.uncertainty = (state.uncertainty + 0.18).min(1.0);     // +18% uncertainty
        state.budget.error_budget_remaining =
            state.budget.error_budget_remaining.saturating_sub(1);   // -1 error budget
        state.side_effect_pressure = 
            (state.side_effect_pressure * 0.5).max(0.1);             // halve side effects
    }

    // Always increase context pressure
    state.context_pressure = (state.context_pressure + 0.03).min(1.0); // +3%

    // Set human dependency if error streak is high
    state.human_dependency = if state.error_streak >= 2 { 0.6 } else { 0.0 };

    // Recompute risk level
    state.risk_level = if state.uncertainty > 0.75 || state.side_effect_pressure > 0.7 {
        RiskLevel::High
    } else if state.uncertainty > 0.45 || state.side_effect_pressure > 0.4 {
        RiskLevel::Medium
    } else {
        RiskLevel::Low
    };
}
```

