  4→use crate::branch::BranchManager;
  5→use crate::manifest::Manifest;
  6→
  7→/// A projection that builds a filesystem manifest and branch state from an event stream.
  8→///
  9→/// `ManifestProjection` implements `lago_core::Projection` and processes
 10→/// file-operation and branch-lifecycle events to maintain an up-to-date
 11→/// in-memory manifest and branch manager.
 12→#[derive(Debug, Clone, Default)]
 13→pub struct ManifestProjection {
 14→    manifest: Manifest,
 15→    branch_manager: BranchManager,
 16→}
 17→
 18→impl ManifestProjection {
 19→    /// Create a new empty projection.
 20→    pub fn new() -> Self {
 21→        Self {
 22→            manifest: Manifest::new(),
 23→            branch_manager: BranchManager::new(),
 24→        }
 25→    }
 26→
 27→    /// Access the current manifest snapshot.
 28→    pub fn manifest(&self) -> &Manifest {
 29→        &self.manifest
 30→    }
 31→
 32→    /// Access the current branch manager.
 33→    pub fn branch_manager(&self) -> &BranchManager {
 34→        &self.branch_manager
 35→    }
 36→}
 37→
 38→impl Projection for ManifestProjection {
 39→    fn on_event(&mut self, event: &EventEnvelope) -> LagoResult<()> {
 40→        match &event.payload {
 41→            // --- File operations
 42→            EventPayload::FileWrite {
 43→                path,
 44→                blob_hash,
 45→                size_bytes,
 46→                content_type,
 47→            } => {
 48→                // Convert aios_protocol::BlobHash -> lago_core::BlobHash
 49→                self.manifest.apply_write(
 50→                    path.clone(),
 51→                    lago_core::BlobHash::from_hex(blob_hash.as_str()),
 52→                    *size_bytes,
 53→                    content_type.clone(),
 54→                    event.timestamp,
 55→                );
 56→            }
 57→
 58→            EventPayload::FileDelete { path } => {
 59→                self.manifest.apply_delete(path);
 60→            }
 61→
 62→            EventPayload::FileRename { old_path, new_path } => {
 63→                self.manifest.apply_rename(old_path, new_path.clone());
 64→            }
 65→
 66→            // --- Branch lifecycle
 67→            EventPayload::BranchCreated {
 68→                new_branch_id,
 69→                fork_point_seq,
 70→                name,
 71→            } => {
 72→                // Convert aios_protocol::BranchId -> lago_core::BranchId
 73→                self.branch_manager.create_branch_with_id(
 74→                    lago_core::BranchId::from_string(new_branch_id.as_str()),
 75→                    name.clone(),
 76→                    *fork_point_seq,
 77→                    Some(event.branch_id.clone()),
 78→                );
 79→            }
 80→
 81→            EventPayload::BranchMerged {
 82→                source_branch_id,
 83→                merge_seq,
 84→            } => {
 85→                // Convert aios_protocol::BranchId -> lago_core::BranchId
 86→                let lago_branch_id = lago_core::BranchId::from_string(source_branch_id.as_str());
 87→                if let Some(branch) = self.branch_manager.get_branch_mut(&lago_branch_id) {
 88→                    branch.head_seq = *merge_seq;
 89→                }
 90→            }
 91→
 92→            // All other event types are not relevant to the filesystem projection
 93→            _ => {}
 94→        }
 95→
 96→        Ok(())
 97→    }
 98→
 99→    fn name(&self) -> &str {
100→        "manifest_projection"
101→    }
102→}
