  5→/// Metadata about a single branch in the versioned filesystem.
  6→///
  7→/// Branches are copy-on-write at the event level: the fork point records
  8→/// which sequence number the branch was forked from, and events are
  9→/// replayed to reconstruct the branch state without duplicating the manifest.
 10→#[derive(Debug, Clone, Serialize, Deserialize)]
 11→pub struct BranchInfo {
 12→    pub branch_id: BranchId,
 13→    pub name: String,
 14→    pub fork_point_seq: SeqNo,
 15→    pub head_seq: SeqNo,
 16→    pub parent_branch: Option<BranchId>,
 17→}
 18→
 19→/// Manages the set of known branches.
 20→#[derive(Debug, Clone, Default, Serialize, Deserialize)]
 21→pub struct BranchManager {
 22→    branches: HashMap<BranchId, BranchInfo>,
 23→}
 24→
 25→impl BranchManager {
 26→    /// Create a new empty branch manager.
 27→    pub fn new() -> Self {
 28→        Self {
 29→            branches: HashMap::new(),
 30→        }
 31→    }
 32→
 33→    /// Create a new branch forked at the given sequence number.
 34→    ///
 35→    /// Returns the newly generated `BranchId`.
 36→    pub fn create_branch(
 37→        &mut self,
 38→        name: String,
 39→        fork_point_seq: SeqNo,
 40→        parent_branch: Option<BranchId>,
 41→    ) -> BranchId {
 42→        let branch_id = BranchId::new();
 43→        let info = BranchInfo {
 44→            branch_id: branch_id.clone(),
 45→            name,
 46→            fork_point_seq,
 47→            head_seq: fork_point_seq,
 48→            parent_branch,
 49→        };
 50→        self.branches.insert(branch_id.clone(), info);
 51→        branch_id
 52→    }
 53→
 54→    /// Create a branch with an explicit ID (used when replaying events
 55→    /// that already carry a `BranchId`).
 56→    pub fn create_branch_with_id(
 57→        &mut self,
 58→        branch_id: BranchId,
 59→        name: String,
 60→        fork_point_seq: SeqNo,
 61→        parent_branch: Option<BranchId>,
 62→    ) {
 63→        let info = BranchInfo {
 64→            branch_id: branch_id.clone(),
 65→            name,
 66→            fork_point_seq,
 67→            head_seq: fork_point_seq,
 68→            parent_branch,
 69→        };
 70→        self.branches.insert(branch_id, info);
 71→    }
 72→
 73→    /// Look up a branch by ID.
 74→    pub fn get_branch(&self, id: &BranchId) -> Option<&BranchInfo> {
 75→        self.branches.get(id)
 76→    }
 77→
 78→    /// Return a mutable reference to a branch (for updating head_seq).
 79→    pub fn get_branch_mut(&mut self, id: &BranchId) -> Option<&mut BranchInfo> {
 80→        self.branches.get_mut(id)
 81→    }
 82→
 83→    /// List all known branches.
 84→    pub fn list_branches(&self) -> Vec<&BranchInfo> {
 85→        self.branches.values().collect()
 86→    }
 87→}
