  1→use std::fs;
  2→use std::path::PathBuf;
  3→
  4→use lago_core::event::{EventEnvelope, EventPayload};
  5→use lago_core::{BranchId, LagoResult, Projection};
  6→use lago_store::BlobStore;
  7→use tracing::{debug, warn};
  8→
  9→/// A projection that synchronizes a Lago manifest state to a real local filesystem.
 10→///
 11→/// `LakeFsSync` binds to a specific `BranchId`. When file operations occur
 12→/// on that branch, it fetches the content from the `BlobStore` and writes it
 13→/// to the corresponding `target_dir` on disk.
 14→///
 15→/// This implements the "Lakebase" architecture pattern where the virtual
 16→/// event-sourced state is perfectly mirrored onto a local POSIX filesystem
 17→/// for raw tool execution and app routing.
 18→pub struct LakeFsSync {
 19→    target_dir: PathBuf,
 20→    blob_store: BlobStore,
 21→    target_branch: BranchId,
 22→}
 23→
 24→impl LakeFsSync {
 25→    /// Create a new filesystem synchronizer bound to a specific directory and branch.
 26→    pub fn new(target_dir: PathBuf, blob_store: BlobStore, target_branch: BranchId) -> Self {
 27→        Self {
 28→            target_dir,
 29→            blob_store,
 30→            target_branch,
 31→        }
 32→    }
 33→
 34→    /// Resolve a virtual manifest path to a local absolute path.
 35→    fn resolve_path(&self, virtual_path: &str) -> PathBuf {
 36→        let relative = virtual_path.trim_start_matches('/');
 37→        self.target_dir.join(relative)
 38→    }
 39→}
 40→
 41→impl Projection for LakeFsSync {
 42→    fn on_event(&mut self, event: &EventEnvelope) -> LagoResult<()> {
 43→        // We only actively sync events that belong to our checked-out branch.
 44→        if event.branch_id != self.target_branch {
 45→            return Ok(());
 46→        }
 47→
 48→        match &event.payload {
 49→            EventPayload::FileWrite {
 50→                path, blob_hash, ..
 51→            } => {
 52→                let fs_path = self.resolve_path(path);
 53→                if let Some(parent) = fs_path.parent() {
 54→                    let _ = fs::create_dir_all(parent);
 55→                }
 56→
 57→                let lago_hash = lago_core::BlobHash::from_hex(blob_hash.as_str());
 58→                match self.blob_store.get(&lago_hash) {
 59→                    Ok(data) => {
 60→                        // In a robust implementation we might only write if the file
 61→                        // differs or doesn't exist. For now, we overwrite.
 62→                        let _ = fs::write(&fs_path, &data);
 63→                        debug!(path = %path, "synced file write to disk");
 64→                    }
 65→                    Err(e) => {
 66→                        warn!(path = %path, error = %e, "failed to get blob for sync");
 67→                    }
 68→                }
 69→            }
 70→            EventPayload::FileDelete { path } => {
 71→                let fs_path = self.resolve_path(path);
 72→                let _ = fs::remove_file(&fs_path);
 73→                debug!(path = %path, "synced file delete to disk");
 74→            }
 75→            EventPayload::FileRename { old_path, new_path } => {
 76→                let old_fs_path = self.resolve_path(old_path);
 77→                let new_fs_path = self.resolve_path(new_path);
 78→                if let Some(parent) = new_fs_path.parent() {
 79→                    let _ = fs::create_dir_all(parent);
 80→                }
 81→                let _ = fs::rename(&old_fs_path, &new_fs_path);
 82→                debug!(old = %old_path, new = %new_path, "synced file rename to disk");
 83→            }
 84→            _ => {}
 85→        }
 86→
 87→        Ok(())
 88→    }
 89→
 90→    fn name(&self) -> &str {
 91→        "lake_fs_sync"
 92→    }
 93→}
