116→    #[test]
117→    fn syncs_writes_to_disk() {
118→        let dir = tempfile::tempdir().unwrap();
119→        let blobs_dir = dir.path().join("blobs");
120→        let target_dir = dir.path().join("workspace");
121→        fs::create_dir_all(&target_dir).unwrap();
122→
123→        let blob_store = BlobStore::open(&blobs_dir).unwrap();
124→        let data = b"hello sync";
125→        let hash = blob_store.put(data).unwrap();
126→
127→        let target_branch = BranchId::from_string("main");
128→        let mut sync = LakeFsSync::new(target_dir.clone(), blob_store, target_branch.clone());
129→
130→        let event = make_envelope(
131→            1,
132→            EventPayload::FileWrite {
133→                path: "/docs/readme.txt".to_string(),
134→                blob_hash: hash.to_string().into(),
135→                size_bytes: data.len() as u64,
