150→        let dir = tempfile::tempdir().unwrap();
151→        let blob_store = BlobStore::open(dir.path().join("blobs")).unwrap();
152→
153→        // Setup sync on "main"
154→        let branch_main = BranchId::from_string("main");
155→        let mut sync = LakeFsSync::new(dir.path().join("ws"), blob_store, branch_main);
156→
157→        let branch_feature = BranchId::from_string("feature");
158→        let event = make_envelope(
159→            1,
160→            EventPayload::FileDelete {
161→                path: "/some.txt".to_string(),
162→            },
163→            &branch_feature, // <-- Different branch
