 29→impl Tool for ReadFileTool {
 30→    fn definition(&self) -> ToolDefinition {
 31→        ToolDefinition {
 32→            name: "read_file".into(),
 33→            description: "Reads a file from the filesystem. Returns content with line numbers and hashes for editing.".into(),
 34→            input_schema: json!({
 35→                "type": "object",
 36→                "properties": {
 37→                    "path": { "type": "string", "description": "Path to the file" }
 38→                },
 39→                "required": ["path"]
 40→            }),
 41→            title: Some("Read File".into()),
 42→            output_schema: None,
 43→            annotations: Some(ToolAnnotations {
 44→                read_only: true,
 45→                idempotent: true,
 46→                ..Default::default()
 47→            }),
 48→            category: Some("filesystem".into()),
 49→            tags: vec!["fs".into(), "read".into()],
 50→            timeout_secs: Some(30),
 51→        }
 52→    }
 53→
 54→    fn execute(&self, call: &ToolCall, _ctx: &ToolContext) -> Result<ToolResult, ToolError> {
 55→        let path_str = call
 56→            .input
 57→            .get("path")
 58→            .and_then(|v| v.as_str())
 59→            .ok_or_else(|| ToolError::InvalidInput {
 60→                message: "Missing or invalid 'path' argument".into(),
 61→            })?;
 62→
 63→        let path = self
 64→            .policy
 65→            .resolve_existing(Path::new(path_str))
 66→            .map_err(|e| ToolError::ExecutionFailed {
 67→                tool_name: "read_file".into(),
 68→                message: e.to_string(),
 69→            })?;
 70→
 71→        let content = fs::read_to_string(&path).map_err(|e| ToolError::ExecutionFailed {
 72→            tool_name: "read_file".into(),
 73→            message: format!("Failed to read file: {e}"),
 74→        })?;
 75→
 76→        let hashed_content = render_hashed_content(&content);
 77→
 78→        Ok(ToolResult {
 79→            call_id: call.call_id.clone(),
 80→            tool_name: call.tool_name.clone(),
 81→            output: json!({ "content": hashed_content, "path": path }),
 82→            content: None,
 83→            is_error: false,
 84→        })
