  1→//! Hashline editing with Blake3 content-addressed line tags.
  2→//!
  3→//! Files are read with line numbers and content hashes. Edits must
  4→//! reference these tags, ensuring the agent edits the version it "sees".
  5→
  6→use aios_protocol::tool::{
  7→    Tool, ToolAnnotations, ToolCall, ToolContext, ToolDefinition, ToolError, ToolResult,
  8→};
  9→use blake3::Hasher;
 10→use praxis_core::workspace::FsPolicy;
 11→use serde::{Deserialize, Serialize};
 12→use serde_json::json;
 13→use std::path::Path;
 14→use thiserror::Error;
 15→
 16→/// A line of content with its hash tag.
 17→#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Eq)]
 18→pub struct HashedLine {
 19→    pub line_no: usize,
 20→    pub tag: String,
 21→    pub text: String,
 22→}
 23→
 24→/// An edit operation referencing a line by its hash tag.
 25→#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Eq)]
 26→#[serde(tag = "op", rename_all = "snake_case")]
 27→pub enum TaggedEditOp {
 28→    ReplaceLine { tag: String, new_text: String },
 29→    InsertAfterTag { tag: String, new_text: String },
 30→    DeleteLine { tag: String },
 31→}
 32→
 33→#[derive(Debug, Clone)]
 34→struct EditableLine {
 35→    anchor_tag: Option<String>,
 36→    text: String,
 37→}
 38→
 39→/// Compute hash tags for all lines in content.
 40→pub fn hash_lines(content: &str) -> Vec<HashedLine> {
 41→    content
 42→        .lines()
 43→        .enumerate()
 44→        .map(|(idx, line)| HashedLine {
 45→            line_no: idx + 1,
 46→            tag: line_tag(idx + 1, line),
 47→            text: line.to_string(),
 48→        })
 49→        .collect()
 50→}
 51→
 52→/// Render content with line numbers and hash tags for display.
 53→pub fn render_hashed_content(content: &str) -> String {
 54→    hash_lines(content)
 55→        .into_iter()
 56→        .map(|line| format!("{:>4} {} | {}", line.line_no, line.tag, line.text))
 57→        .collect::<Vec<_>>()
 58→        .join("\n")
 59→}
 60→
 61→/// Apply a sequence of tagged edit operations to content.
 62→pub fn apply_tagged_edits(content: &str, ops: &[TaggedEditOp]) -> Result<String, EditError> {
 63→    let initial_lines = hash_lines(content);
 64→
 65→    if initial_lines.is_empty() && !ops.is_empty() {
 66→        return Err(EditError::EmptyContent);
 67→    }
 68→
 69→    let mut editable: Vec<EditableLine> = initial_lines
 70→        .iter()
 71→        .map(|line| EditableLine {
 72→            anchor_tag: Some(line.tag.clone()),
 73→            text: line.text.clone(),
 74→        })
 75→        .collect();
 76→
 77→    for op in ops {
 78→        match op {
 79→            TaggedEditOp::ReplaceLine { tag, new_text } => {
 80→                let idx = find_anchor_index(&editable, tag)?;
 81→                editable[idx].text = new_text.clone();
 82→            }
 83→            TaggedEditOp::InsertAfterTag { tag, new_text } => {
 84→                let idx = find_anchor_index(&editable, tag)?;
 85→                editable.insert(
 86→                    idx + 1,
 87→                    EditableLine {
 88→                        anchor_tag: None,
 89→                        text: new_text.clone(),
 90→                    },
 91→                );
 92→            }
 93→            TaggedEditOp::DeleteLine { tag } => {
 94→                let idx = find_anchor_index(&editable, tag)?;
 95→                editable.remove(idx);
 96→            }
 97→        }
 98→    }
 99→
100→    Ok(editable
101→        .into_iter()
102→        .map(|line| line.text)
103→        .collect::<Vec<_>>()
104→        .join("\n"))
105→}
106→
107→fn find_anchor_index(lines: &[EditableLine], tag: &str) -> Result<usize, EditError> {
108→    lines
109→        .iter()
110→        .position(|line| line.anchor_tag.as_deref() == Some(tag))
111→        .ok_or_else(|| EditError::StaleTag(tag.to_string()))
112→}
113→
114→fn line_tag(line_no: usize, text: &str) -> String {
115→    let mut hasher = Hasher::new();
116→    hasher.update(line_no.to_string().as_bytes());
117→    hasher.update(b":");
118→    hasher.update(text.as_bytes());
119→    let digest = hasher.finalize().to_hex().to_string();
120→    digest.chars().take(8).collect()
121→}
122→
123→/// Errors from the hashline editing system.
124→#[derive(Debug, Error)]
125→pub enum EditError {
126→    #[error("input content is empty; tags are required before edit")]
127→    EmptyContent,
128→    #[error("tag is stale or missing in current content: {0}")]
129→    StaleTag(String),
130→}
