132→// ── EditFileTool ──────────────────────────────────────────────────────
133→
134→/// Tool that applies hashline edits to files.
135→pub struct EditFileTool {
136→    policy: FsPolicy,
137→}
138→
139→impl EditFileTool {
140→    pub fn new(policy: FsPolicy) -> Self {
141→        Self { policy }
142→    }
143→}
144→
145→impl Tool for EditFileTool {
146→    fn definition(&self) -> ToolDefinition {
147→        ToolDefinition {
148→            name: "edit_file".into(),
149→            description: "Edits a file using line tags. Operations: replace_line, insert_after_tag, delete_line.".into(),
150→            input_schema: json!({
151→                "type": "object",
152→                "properties": {
153→                    "path": { "type": "string", "description": "Path to the file" },
154→                    "ops": {
155→                        "type": "array",
156→                        "items": {
157→                            "type": "object",
158→                            "oneOf": [
159→                                { "properties": { "op": { "const": "replace_line" }, "tag": { "type": "string" }, "new_text": { "type": "string" } }, "required": ["op", "tag", "new_text"] },
160→                                { "properties": { "op": { "const": "insert_after_tag" }, "tag": { "type": "string" }, "new_text": { "type": "string" } }, "required": ["op", "tag", "new_text"] },
161→                                { "properties": { "op": { "const": "delete_line" }, "tag": { "type": "string" } }, "required": ["op", "tag"] }
162→                            ]
163→                        }
164→                    }
165→                },
166→                "required": ["path", "ops"]
167→            }),
168→            title: Some("Edit File".into()),
169→            output_schema: None,
170→            annotations: Some(ToolAnnotations {
171→                destructive: true,
172→                ..Default::default()
173→            }),
174→            category: Some("filesystem".into()),
175→            tags: vec!["fs".into(), "edit".into()],
176→            timeout_secs: Some(30),
177→        }
178→    }
179→
180→    fn execute(&self, call: &ToolCall, _ctx: &ToolContext) -> Result<ToolResult, ToolError> {
181→        let path_str = call
182→            .input
183→            .get("path")
184→            .and_then(|v| v.as_str())
185→            .ok_or_else(|| ToolError::InvalidInput {
186→                message: "Missing or invalid 'path' argument".into(),
187→            })?;
188→
189→        let ops_value = call
190→            .input
191→            .get("ops")
192→            .ok_or_else(|| ToolError::InvalidInput {
193→                message: "Missing 'ops' argument".into(),
194→            })?;
195→
196→        let ops: Vec<TaggedEditOp> =
197→            serde_json::from_value(ops_value.clone()).map_err(|e| ToolError::InvalidInput {
198→                message: format!("Invalid 'ops' format: {e}"),
199→            })?;
200→
201→        let path = self
202→            .policy
203→            .resolve_for_write(Path::new(path_str))
204→            .map_err(|e| ToolError::PolicyViolation {
205→                message: e.to_string(),
206→            })?;
207→
208→        let content = std::fs::read_to_string(&path).map_err(|e| ToolError::ExecutionFailed {
209→            tool_name: "edit_file".into(),
210→            message: format!("Failed to read file: {e}"),
211→        })?;
212→
213→        let new_content =
214→            apply_tagged_edits(&content, &ops).map_err(|e| ToolError::ExecutionFailed {
215→                tool_name: "edit_file".into(),
216→                message: format!("Edit failed: {e}"),
217→            })?;
218→
219→        std::fs::write(&path, &new_content).map_err(|e| ToolError::ExecutionFailed {
220→            tool_name: "edit_file".into(),
221→            message: format!("Failed to write file: {e}"),
222→        })?;
223→
224→        let hashed_content = render_hashed_content(&new_content);
225→
226→        Ok(ToolResult {
227→            call_id: call.call_id.clone(),
228→            tool_name: call.tool_name.clone(),
229→            output: json!({ "success": true, "content": hashed_content, "path": path }),
230→            content: None,
231→            is_error: false,
232→        })
233→    }
234→}
