  1→//! Shell command execution tool.
  2→//!
  3→//! The `BashTool` wraps the sandbox's `CommandRunner` to execute
  4→//! shell commands within policy constraints.
  5→
  6→use aios_protocol::tool::{
  7→    Tool, ToolAnnotations, ToolCall, ToolContext, ToolDefinition, ToolError, ToolResult,
  8→};
  9→use praxis_core::sandbox::{CommandRequest, CommandRunner, SandboxPolicy};
 10→use serde_json::json;
 11→use std::path::PathBuf;
 12→
 13→/// Tool that executes bash commands within the sandbox.
 14→pub struct BashTool {
 15→    policy: SandboxPolicy,
 16→    runner: Box<dyn CommandRunner>,
 17→}
 18→
 19→impl BashTool {
 20→    pub fn new(policy: SandboxPolicy, runner: Box<dyn CommandRunner>) -> Self {
 21→        Self { policy, runner }
 22→    }
 23→}
 24→
 25→impl Tool for BashTool {
 26→    fn definition(&self) -> ToolDefinition {
 27→        ToolDefinition {
 28→            name: "bash".into(),
 29→            description: "Executes a bash command in the sandbox.".into(),
 30→            input_schema: json!({
 31→                "type": "object",
 32→                "properties": {
 33→                    "command": { "type": "string", "description": "The command line to execute" },
 34→                    "cwd": { "type": "string", "description": "Working directory (optional)" }
 35→                },
 36→                "required": ["command"]
 37→            }),
 38→            title: Some("Bash Command".into()),
 39→            output_schema: None,
 40→            annotations: Some(ToolAnnotations {
 41→                destructive: true,
 42→                open_world: true,
 43→                requires_confirmation: true,
 44→                ..Default::default()
 45→            }),
 46→            category: Some("shell".into()),
 47→            tags: vec!["shell".into(), "exec".into()],
 48→            timeout_secs: Some(60),
 49→        }
 50→    }
 51→
 52→    fn execute(&self, call: &ToolCall, _ctx: &ToolContext) -> Result<ToolResult, ToolError> {
 53→        let command_line = call
 54→            .input
 55→            .get("command")
 56→            .and_then(|v| v.as_str())
 57→            .ok_or_else(|| ToolError::InvalidInput {
 58→                message: "Missing 'command' argument".into(),
 59→            })?;
 60→
 61→        let cwd = call
 62→            .input
 63→            .get("cwd")
 64→            .and_then(|v| v.as_str())
 65→            .map(PathBuf::from)
 66→            .unwrap_or_else(|| self.policy.workspace_root.clone());
 67→
 68→        let request = CommandRequest {
 69→            executable: "/bin/bash".into(),
 70→            args: vec!["-c".into(), command_line.into()],
 71→            cwd,
 72→            env: vec![],
 73→        };
 74→
 75→        let result =
 76→            self.runner
 77→                .run(&self.policy, &request)
 78→                .map_err(|e| ToolError::ExecutionFailed {
 79→                    tool_name: "bash".into(),
 80→                    message: e.to_string(),
 81→                })?;
 82→
 83→        Ok(ToolResult {
 84→            call_id: call.call_id.clone(),
 85→            tool_name: call.tool_name.clone(),
 86→            output: json!({
 87→                "exit_code": result.exit_code,
 88→                "stdout": result.stdout,
 89→                "stderr": result.stderr
 90→            }),
 91→            content: None,
 92→            is_error: false,
 93→        })
 94→    }
 95→}
 96→
