  1→//! Agent memory tools (file-based read/write).
  2→//!
  3→//! Memory is stored as markdown files keyed by name within
  4→//! a configured memory directory.
  5→
  6→use aios_protocol::tool::{
  7→    Tool, ToolAnnotations, ToolCall, ToolContext, ToolDefinition, ToolError, ToolResult,
  8→};
  9→use serde_json::json;
 10→use std::fs;
 11→use std::path::PathBuf;
 12→
 13→// ── ReadMemoryTool ───────────────────────────────────────────────────
 14→
 15→/// Reads the agent's persistent memory file by key.
 16→pub struct ReadMemoryTool {
 17→    memory_dir: PathBuf,
 18→}
 19→
 20→impl ReadMemoryTool {
 21→    pub fn new(memory_dir: PathBuf) -> Self {
 22→        Self { memory_dir }
 23→    }
 24→}
 25→
 26→impl Tool for ReadMemoryTool {
 27→    fn definition(&self) -> ToolDefinition {
 28→        ToolDefinition {
 29→            name: "read_memory".into(),
 30→            description: "Read the agent's persistent memory file by key.".into(),
 31→            input_schema: json!({
 32→                "type": "object",
 33→                "properties": {
 34→                    "key": { "type": "string", "description": "Memory key (e.g. 'global', 'session', or custom name)" }
 35→                },
 36→                "required": ["key"]
 37→            }),
 38→            title: Some("Read Memory".into()),
 39→            output_schema: None,
 40→            annotations: Some(ToolAnnotations {
 41→                read_only: true,
 42→                idempotent: true,
 43→                ..Default::default()
 44→            }),
 45→            category: Some("memory".into()),
 46→            tags: vec!["memory".into(), "read".into()],
 47→            timeout_secs: Some(10),
 48→        }
 49→    }
 50→
 51→    fn execute(&self, call: &ToolCall, _ctx: &ToolContext) -> Result<ToolResult, ToolError> {
 52→        let key = call
 53→            .input
 54→            .get("key")
 55→            .and_then(|v| v.as_str())
 56→            .ok_or_else(|| ToolError::InvalidInput {
 57→                message: "Missing or invalid 'key' argument".into(),
 58→            })?;
 59→
 60→        validate_memory_key(key).map_err(|msg| ToolError::InvalidInput { message: msg })?;
 61→
 62→        let file_path = self.memory_dir.join(format!("{key}.md"));
 63→
 64→        if file_path.exists() {
 65→            let content =
 66→                fs::read_to_string(&file_path).map_err(|e| ToolError::ExecutionFailed {
 67→                    tool_name: "read_memory".into(),
 68→                    message: format!("Failed to read memory file: {e}"),
 69→                })?;
 70→
 71→            Ok(ToolResult {
 72→                call_id: call.call_id.clone(),
 73→                tool_name: call.tool_name.clone(),
 74→                output: json!({ "content": content, "exists": true, "path": file_path }),
 75→                content: None,
 76→                is_error: false,
 77→            })
 78→        } else {
 79→            Ok(ToolResult {
 80→                call_id: call.call_id.clone(),
 81→                tool_name: call.tool_name.clone(),
 82→                output: json!({ "content": null, "exists": false, "path": file_path }),
 83→                content: None,
 84→                is_error: false,
 85→            })
 86→        }
 87→    }
 88→}
 89→
 90→// ── WriteMemoryTool ──────────────────────────────────────────────────
 91→
 92→/// Writes to the agent's persistent memory file by key.
 93→pub struct WriteMemoryTool {
 94→    memory_dir: PathBuf,
 95→}
 96→
 97→impl WriteMemoryTool {
 98→    pub fn new(memory_dir: PathBuf) -> Self {
 99→        Self { memory_dir }
100→    }
101→}
102→
103→impl Tool for WriteMemoryTool {
104→    fn definition(&self) -> ToolDefinition {
105→        ToolDefinition {
106→            name: "write_memory".into(),
107→            description: "Write to the agent's persistent memory file by key.".into(),
108→            input_schema: json!({
109→                "type": "object",
110→                "properties": {
111→                    "key": { "type": "string", "description": "Memory key (e.g. 'global', 'session', or custom name)" },
112→                    "content": { "type": "string", "description": "Markdown content to write" }
113→                },
114→                "required": ["key", "content"]
115→            }),
116→            title: Some("Write Memory".into()),
117→            output_schema: None,
118→            annotations: Some(ToolAnnotations {
119→                destructive: true,
120→                ..Default::default()
121→            }),
122→            category: Some("memory".into()),
123→            tags: vec!["memory".into(), "write".into()],
124→            timeout_secs: Some(10),
125→        }
126→    }
127→
128→    fn execute(&self, call: &ToolCall, _ctx: &ToolContext) -> Result<ToolResult, ToolError> {
129→        let key = call
130→            .input
131→            .get("key")
132→            .and_then(|v| v.as_str())
133→            .ok_or_else(|| ToolError::InvalidInput {
134→                message: "Missing or invalid 'key' argument".into(),
135→            })?;
136→
137→        let content = call
138→            .input
139→            .get("content")
140→            .and_then(|v| v.as_str())
141→            .ok_or_else(|| ToolError::InvalidInput {
142→                message: "Missing or invalid 'content' argument".into(),
143→            })?;
144→
145→        validate_memory_key(key).map_err(|msg| ToolError::InvalidInput { message: msg })?;
146→
147→        fs::create_dir_all(&self.memory_dir).map_err(|e| ToolError::ExecutionFailed {
148→            tool_name: "write_memory".into(),
149→            message: format!("Failed to create memory directory: {e}"),
150→        })?;
151→
152→        let file_path = self.memory_dir.join(format!("{key}.md"));
153→
154→        fs::write(&file_path, content).map_err(|e| ToolError::ExecutionFailed {
155→            tool_name: "write_memory".into(),
156→            message: format!("Failed to write memory file: {e}"),
157→        })?;
158→
159→        Ok(ToolResult {
160→            call_id: call.call_id.clone(),
161→            tool_name: call.tool_name.clone(),
162→            output: json!({ "success": true, "path": file_path }),
163→            content: None,
164→            is_error: false,
165→        })
166→    }
167→}
168→
169→/// Validate that a memory key is safe (alphanumeric, hyphens, underscores).
170→pub fn validate_memory_key(key: &str) -> Result<(), String> {
171→    if key.is_empty() {
172→        return Err("Memory key cannot be empty".into());
173→    }
174→    if key.len() > 64 {
175→        return Err("Memory key too long (max 64 characters)".into());
176→    }
177→    if !key
178→        .chars()
179→        .all(|c| c.is_alphanumeric() || c == '-' || c == '_')
180→    {
181→        return Err(
182→            "Memory key must contain only alphanumeric characters, hyphens, and underscores".into(),
183→        );
184→    }
185→    if key.starts_with('.') || key.contains("..") {
186→        return Err("Memory key cannot start with '.' or contain '..'".into());
187→    }
188→    Ok(())
189→}
