  9→/// Filesystem policy that enforces workspace boundaries.
 10→///
 11→/// All paths must resolve to locations within the workspace root.
 12→/// Symlinks are resolved before validation to prevent traversal.
 13→#[derive(Debug, Clone)]
 14→pub struct FsPolicy {
 15→    workspace_root: PathBuf,
 16→}
 17→
 18→impl FsPolicy {
 19→    /// Create a new policy rooted at the given directory.
 20→    pub fn new(workspace_root: impl Into<PathBuf>) -> Self {
 21→        Self {
 22→            workspace_root: workspace_root.into(),
 23→        }
 24→    }
 25→
 26→    /// Return the workspace root.
 27→    pub fn workspace_root(&self) -> &Path {
 28→        &self.workspace_root
 29→    }
 30→
 31→    /// Resolve an existing path, ensuring it's within the workspace.
 32→    ///
 33→    /// The path must exist. Returns the canonicalized absolute path.
 34→    pub fn resolve_existing(&self, candidate: &Path) -> PraxisResult<PathBuf> {
 35→        let joined = if candidate.is_absolute() {
 36→            candidate.to_path_buf()
 37→        } else {
 38→            self.workspace_root.join(candidate)
 39→        };
 40→        let canonical = joined.canonicalize()?;
 41→        self.ensure_within_root(&canonical)?;
 42→        Ok(canonical)
 43→    }
 44→
 45→    /// Resolve a path for writing. The parent must exist and be within workspace,
 46→    /// but the file itself may not exist yet.
 47→    pub fn resolve_for_write(&self, candidate: &Path) -> PraxisResult<PathBuf> {
 48→        let joined = if candidate.is_absolute() {
 49→            candidate.to_path_buf()
 50→        } else {
 51→            self.workspace_root.join(candidate)
 52→        };
 53→        let parent = joined
 54→            .parent()
 55→            .ok_or_else(|| PraxisError::PathOutsideWorkspace {
 56→                path: joined.display().to_string(),
 57→            })?;
 58→        let canonical_parent = parent.canonicalize()?;
 59→        self.ensure_within_root(&canonical_parent)?;
 60→        Ok(canonical_parent.join(joined.file_name().unwrap()))
 61→    }
 62→
 63→    /// Validate that a canonical path is within the workspace root.
 64→    fn ensure_within_root(&self, candidate: &Path) -> PraxisResult<()> {
 65→        let canonical_root = self.workspace_root.canonicalize().map_err(|e| {
 66→            PraxisError::WorkspaceViolation(format!("cannot resolve workspace root: {e}"))
 67→        })?;
 68→        if candidate.starts_with(&canonical_root) {
 69→            Ok(())
 70→        } else {
 71→            Err(PraxisError::PathOutsideWorkspace {
 72→                path: candidate.display().to_string(),
 73→            })
 74→        }
 75→    }
 76→
 77→    /// Validate and resolve a path, ensuring it's within the workspace.
 78→    ///
 79→    /// Returns the canonicalized absolute path on success.
 80→    pub fn resolve(&self, path: &str) -> PraxisResult<PathBuf> {
 81→        let target = if Path::new(path).is_absolute() {
 82→            PathBuf::from(path)
 83→        } else {
 84→            self.workspace_root.join(path)
 85→        };
 86→
 87→        // For paths that don't exist yet, validate the parent
 88→        if target.exists() {
 89→            let canonical = target.canonicalize()?;
 90→            let canonical_root = self.workspace_root.canonicalize().map_err(|e| {
 91→                PraxisError::WorkspaceViolation(format!("cannot resolve workspace root: {e}"))
 92→            })?;
 93→            if !canonical.starts_with(&canonical_root) {
 94→                return Err(PraxisError::PathOutsideWorkspace {
 95→                    path: path.to_string(),
 96→                });
 97→            }
 98→            Ok(canonical)
 99→        } else {
100→            // Path doesn't exist — validate the parent
101→            let parent = target
102→                .parent()
103→                .ok_or_else(|| PraxisError::PathOutsideWorkspace {
104→                    path: path.to_string(),
105→                })?;
106→            if parent.exists() {
107→                let canonical_parent = parent.canonicalize()?;
108→                let canonical_root = self.workspace_root.canonicalize().map_err(|e| {
109→                    PraxisError::WorkspaceViolation(format!("cannot resolve workspace root: {e}"))
110→                })?;
111→                if !canonical_parent.starts_with(&canonical_root) {
112→                    return Err(PraxisError::PathOutsideWorkspace {
113→                        path: path.to_string(),
114→                    });
115→                }
116→                Ok(target)
117→            } else {
118→                Err(PraxisError::PathOutsideWorkspace {
119→                    path: path.to_string(),
120→                })
121→            }
122→        }
123→    }
124→
125→    /// Return a path relative to the workspace root, if it's within bounds.
126→    pub fn relative(&self, absolute_path: &Path) -> Option<PathBuf> {
127→        let canonical_root = self.workspace_root.canonicalize().ok()?;
128→        let canonical_path = absolute_path.canonicalize().ok()?;
129→        canonical_path
130→            .strip_prefix(&canonical_root)
131→            .ok()
132→            .map(|p| p.to_path_buf())
133→    }
134→}
