 45→#[async_trait::async_trait]
 46→impl arcan_aios_adapters::tools::ToolHarnessObserver for LakeFsObserver {
 47→    async fn post_execute(&self, session_id: String, _tool_name: String) {
 48→        // We skip memory tools since they don't modify the FS directly, and bash since we might want more granular control, but for now we trace everything.
 49→        let sess_id = SessionId::from_string(session_id.clone());
 50→        let branch_id = BranchId::from_string("main");
 51→
 52→        let events = match self
 53→            .journal
 54→            .read(EventQuery::new().session(lago_core::SessionId::from_string(session_id)))
 55→            .await
 56→        {
 57→            Ok(events) => events,
 58→            Err(e) => {
 59→                tracing::warn!(%e, "LakeFsObserver: failed to read journal");
 60→                return;
 61→            }
 62→        };
 63→
 64→        let mut proj = ManifestProjection::new();
 65→        for e in events {
 66→            if e.branch_id == branch_id {
 67→                let _ = proj.on_event(&e);
 68→            }
 69→        }
 70→
 71→        let current_manifest = proj.manifest().clone();
 72→
 73→        // Run the synchronous snapshot + diff on a blocking thread to avoid
 74→        // stalling the tokio worker (the walk/hash can take seconds on large workspaces).
 75→        let workspace_root = self.workspace_root.clone();
 76→        let blob_store = self.blob_store.clone();
 77→        let snapshot_result = tokio::task::spawn_blocking(move || {
 78→            let new_manifest = lago_fs::snapshot(&workspace_root, &current_manifest, &blob_store)?;
 79→            let diffs = lago_fs::diff(&current_manifest, &new_manifest);
 80→            Ok::<_, lago_core::LagoError>(diffs)
 81→        })
 82→        .await;
 83→
 84→        let diffs = match snapshot_result {
 85→            Ok(Ok(d)) => d,
 86→            Ok(Err(e)) => {
 87→                tracing::warn!(%e, "LakeFsObserver: failed to snapshot workspace");
 88→                return;
 89→            }
 90→            Err(e) => {
 91→                tracing::warn!(%e, "LakeFsObserver: snapshot task panicked");
 92→                return;
 93→            }
 94→        };
 95→        if diffs.is_empty() {
 96→            return;
 97→        }
 98→
 99→        tracing::info!(
100→            diff_count = diffs.len(),
101→            "LakeFsObserver: workspace changed, emitting events"
102→        );
103→
104→        for diff in diffs {
105→            let payload = match diff {
106→                DiffEntry::Added { path, entry } => EventPayload::FileWrite {
107→                    path,
108→                    blob_hash: entry.blob_hash.into(),
109→                    size_bytes: entry.size_bytes,
110→                    content_type: entry.content_type,
111→                },
112→                DiffEntry::Modified {
113→                    path, new: entry, ..
114→                } => EventPayload::FileWrite {
115→                    path,
116→                    blob_hash: entry.blob_hash.into(),
117→                    size_bytes: entry.size_bytes,
118→                    content_type: entry.content_type,
119→                },
120→                DiffEntry::Removed { path, .. } => EventPayload::FileDelete { path },
121→            };
122→
123→            let envelope = EventEnvelope {
124→                event_id: EventId::new(),
125→                session_id: sess_id.clone(),
126→                branch_id: branch_id.clone(),
127→                run_id: None,
128→                seq: 0,
129→                timestamp: EventEnvelope::now_micros(),
130→                parent_id: None,
131→                payload,
132→                metadata: std::collections::HashMap::new(),
133→                schema_version: 1,
134→            };
135→
136→            if let Err(e) = self.journal.append(envelope).await {
137→                tracing::warn!(%e, "LakeFsObserver: failed to append event");
138→            }
139→        }
140→    }
141→}
