#### Phase 1: FsPort Trait (praxis-core)

**File**: `praxis/crates/praxis-core/src/fs_port.rs` (NEW)

```rust
use crate::error::{PraxisError, PraxisResult};
use std::path::{Path, PathBuf};

/// Metadata for filesystem entries
#[derive(Debug, Clone)]
pub struct FsMetadata {
    pub is_file: bool,
    pub is_dir: bool,
    pub size_bytes: u64,
}

/// Directory entry
#[derive(Debug, Clone)]
pub struct FsDirEntry {
    pub name: String,
    pub is_file: bool,
    pub is_dir: bool,
}

/// Filesystem port - abstracts filesystem operations with workspace enforcement.
///
/// All paths are validated against the workspace root before operations.
/// Implementations may add tracking, caching, or other cross-cutting concerns.
pub trait FsPort: Send + Sync {
    /// Return the workspace root path
    fn workspace_root(&self) -> &Path;

    /// Resolve a path (existing file/dir) within workspace bounds
    ///
    /// Returns canonicalized absolute path. Rejects paths outside workspace.
    fn resolve(&self, path: &Path) -> PraxisResult<PathBuf>;

    /// Resolve a path for writing (parent must exist, file may not)
    ///
    /// Returns validated path. Rejects if parent is outside workspace.
    fn resolve_for_write(&self, path: &Path) -> PraxisResult<PathBuf>;

    /// Read file as UTF-8 string
    fn read_to_string(&self, path: &Path) -> PraxisResult<String>;

    /// Read file as raw bytes
    fn read_bytes(&self, path: &Path) -> PraxisResult<Vec<u8>>;

    /// Write bytes to file (creates parent dirs if needed)
    fn write(&self, path: &Path, content: &[u8]) -> PraxisResult<()>;

    /// Check if path exists
    fn exists(&self, path: &Path) -> bool;

    /// Get file/directory metadata
    fn metadata(&self, path: &Path) -> PraxisResult<FsMetadata>;

    /// List directory contents
    fn read_dir(&self, path: &Path) -> PraxisResult<Vec<FsDirEntry>>;

    /// Create directory and all parents
    fn create_dir_all(&self, path: &Path) -> PraxisResult<()>;

    /// Compute path relative to workspace root (if within bounds)
    fn relative(&self, absolute_path: &Path) -> Option<PathBuf>;
}
```

**File**: `praxis/crates/praxis-core/src/local_fs.rs` (NEW)

```rust
use super::fs_port::{FsDirEntry, FsMetadata, FsPort};
use crate::error::{PraxisError, PraxisResult};
use crate::workspace::FsPolicy;
use std::fs;
use std::path::{Path, PathBuf};

/// Local filesystem implementation using std::fs
///
/// Wraps FsPolicy for workspace boundary enforcement.
/// This is the default, backward-compatible implementation.
#[derive(Clone)]
pub struct LocalFs {
    policy: FsPolicy,
}

impl LocalFs {
    pub fn new(policy: FsPolicy) -> Self {
        Self { policy }
    }
}

impl FsPort for LocalFs {
    fn workspace_root(&self) -> &Path {
        self.policy.workspace_root()
    }

    fn resolve(&self, path: &Path) -> PraxisResult<PathBuf> {
        self.policy.resolve_existing(path)
    }

    fn resolve_for_write(&self, path: &Path) -> PraxisResult<PathBuf> {
        self.policy.resolve_for_write(path)
    }

    fn read_to_string(&self, path: &Path) -> PraxisResult<String> {
        let resolved = self.resolve(path)?;
        fs::read_to_string(&resolved).map_err(Into::into)
    }

    fn read_bytes(&self, path: &Path) -> PraxisResult<Vec<u8>> {
        let resolved = self.resolve(path)?;
        fs::read(&resolved).map_err(Into::into)
    }

    fn write(&self, path: &Path, content: &[u8]) -> PraxisResult<()> {
        let resolved = self.resolve_for_write(path)?;

        // Create parent dirs if needed
        if let Some(parent) = resolved.parent() {
            fs::create_dir_all(parent)?;
        }

        fs::write(&resolved, content).map_err(Into::into)
    }

    fn exists(&self, path: &Path) -> bool {
        path.exists()
    }

    fn metadata(&self, path: &Path) -> PraxisResult<FsMetadata> {
        let resolved = self.resolve(path)?;
        let meta = fs::metadata(&resolved)?;
        Ok(FsMetadata {
            is_file: meta.is_file(),
            is_dir: meta.is_dir(),
            size_bytes: meta.len(),
        })
    }

    fn read_dir(&self, path: &Path) -> PraxisResult<Vec<FsDirEntry>> {
        let resolved = self.resolve(path)?;
        fs::read_dir(&resolved)?
            .filter_map(Result::ok)
            .map(|entry| {
                let path = entry.path();
                Ok(FsDirEntry {
                    name: entry.file_name().to_string_lossy().to_string(),
                    is_file: path.is_file(),
                    is_dir: path.is_dir(),
                })
            })
            .collect()
    }

    fn create_dir_all(&self, path: &Path) -> PraxisResult<()> {
        let resolved = self.resolve_for_write(path)?;
        fs::create_dir_all(&resolved).map_err(Into::into)
    }

    fn relative(&self, absolute_path: &Path) -> Option<PathBuf> {
        self.policy.relative(absolute_path)
    }
}

