**GlobTool special case** (uses workspace_root for pattern construction):

```rust
pub struct GlobTool {
    fs: Arc<dyn FsPort>,
}

impl Tool for GlobTool {
    fn execute(&self, call: &ToolCall, _ctx: &ToolContext) -> Result<ToolResult, ToolError> {
        let pattern = call.input.get("pattern")...;
        let base_dir = call.input.get("path")
            .map(PathBuf::from)
            .unwrap_or_else(|| self.fs.workspace_root().to_path_buf());

        let base_dir = self.fs.resolve(&base_dir)?;
        let full_pattern = base_dir.join(pattern).display().to_string();

        let matches: Vec<String> = glob::glob(&full_pattern)?
            .filter_map(Result::ok)
            .filter(|path| self.fs.resolve(path).is_ok())
            .map(|path| {
                self.fs.relative(&path)
                    .map(|p| p.display().to_string())
                    .unwrap_or_else(|| path.display().to_string())
            })
            .collect();

        Ok(ToolResult { output: json!({ "matches": matches, "count": matches.len() }), ... })
    }
}
```

**GrepTool special case** (validates via FsPort, streams via std::fs):

```rust
pub struct GrepTool {
    fs: Arc<dyn FsPort>,
}

impl Tool for GrepTool {
    fn execute(&self, call: &ToolCall, _ctx: &ToolContext) -> Result<ToolResult, ToolError> {
        let regex = Regex::new(pattern_str)?;
        let base_dir = self.fs.resolve(&base_dir)?;

        for entry in walkdir::WalkDir::new(&base_dir)... {
            let path = entry.path();

            // Validate workspace boundary
            if self.fs.resolve(path).is_err() {
                continue;
            }

            // Stream file directly (read-only, no tracking needed)
            let Ok(file) = std::fs::File::open(path) else { continue; };
            let reader = BufReader::new(file);

            for (line_no, line) in reader.lines().enumerate() {
                if regex.is_match(&line?) {
                    let rel_path = self.fs.relative(path)
                        .unwrap_or_else(|| path.to_path_buf());
                    matches.push(json!({ "file": rel_path, "line": line_no + 1, "text": line }));
                }
            }
        }
        Ok(ToolResult { ... })
    }
}
