        let policy = FsPolicy::new(dir.path());
        let local_fs = LocalFs::new(policy);

        let blob_dir = dir.path().join("blobs");
        let blob_store = Arc::new(BlobStore::open(&blob_dir).unwrap());

        let journal_dir = dir.path().join("journal");
        let journal = Arc::new(RedbJournal::open(&journal_dir).unwrap());

        let (tx, rx) = mpsc::channel(1000);
        let tracked_fs = LagoTrackedFs::new(local_fs, blob_store.clone(), tx);

        let session_id = SessionId::from_string("test-session");
        let branch_id = BranchId::from_string("main");

        // Spawn event writer
        let journal_clone = journal.clone();
        let writer_task = tokio::spawn(run_event_writer(
            rx,
            journal_clone,
            session_id.clone(),
            branch_id.clone(),
        ));

        // Write file via tracked_fs
        tracked_fs.write(Path::new("test.txt"), b"hello world").unwrap();

        // Allow async task to process
        tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;

        // Verify event in journal
        let events = journal
            .read(lago_core::EventQuery::new().session(session_id))
            .await
            .unwrap();

        assert_eq!(events.len(), 1);
        match &events[0].payload {
            EventPayload::FileWrite { path, size_bytes, .. } => {
                assert_eq!(path, "test.txt");
                assert_eq!(*size_bytes, 11);
            }
            _ => panic!("Expected FileWrite event"),
        }

        // Cleanup
        drop(tracked_fs);
        writer_task.await.unwrap();
    }
