```rust
use crate::error::{PraxisError, PraxisResult};
use std::path::{Path, PathBuf};

/// Metadata for filesystem entries
#[derive(Debug, Clone)]
pub struct FsMetadata {
    pub is_file: bool,
    pub is_dir: bool,
    pub size_bytes: u64,
}

/// Directory entry
#[derive(Debug, Clone)]
pub struct FsDirEntry {
    pub name: String,
    pub is_file: bool,
    pub is_dir: bool,
}

/// Filesystem port - abstracts filesystem operations with workspace enforcement.
///
/// All paths are validated against the workspace root before operations.
/// Implementations may add tracking, caching, or other cross-cutting concerns.
pub trait FsPort: Send + Sync {
    /// Return the workspace root path
    fn workspace_root(&self) -> &Path;

    /// Resolve a path (existing file/dir) within workspace bounds
    ///
    /// Returns canonicalized absolute path. Rejects paths outside workspace.
    fn resolve(&self, path: &Path) -> PraxisResult<PathBuf>;

    /// Resolve a path for writing (parent must exist, file may not)
    ///
    /// Returns validated path. Rejects if parent is outside workspace.
    fn resolve_for_write(&self, path: &Path) -> PraxisResult<PathBuf>;

    /// Read file as UTF-8 string
    fn read_to_string(&self, path: &Path) -> PraxisResult<String>;

    /// Read file as raw bytes
    fn read_bytes(&self, path: &Path) -> PraxisResult<Vec<u8>>;

    /// Write bytes to file (creates parent dirs if needed)
    fn write(&self, path: &Path, content: &[u8]) -> PraxisResult<()>;

    /// Check if path exists
    fn exists(&self, path: &Path) -> bool;

    /// Get file/directory metadata
    fn metadata(&self, path: &Path) -> PraxisResult<FsMetadata>;

    /// List directory contents
    fn read_dir(&self, path: &Path) -> PraxisResult<Vec<FsDirEntry>>;

    /// Create directory and all parents
    fn create_dir_all(&self, path: &Path) -> PraxisResult<()>;

    /// Compute path relative to workspace root (if within bounds)
    fn relative(&self, absolute_path: &Path) -> Option<PathBuf>;
}
```

