```rust
use lago_core::{BlobHash, BranchId, EventEnvelope, EventId, EventPayload, Journal, SessionId};
use lago_store::BlobStore;
use praxis_core::{FsPort, FsMetadata, FsDirEntry, LocalFs};
use std::path::{Path, PathBuf};
use std::sync::Arc;
use tokio::sync::mpsc;
use tracing::{debug, warn};

/// Filesystem write notification
#[derive(Debug, Clone)]
pub struct FsWriteNotification {
    pub path: PathBuf,
    pub blob_hash: BlobHash,
    pub size_bytes: u64,
    pub content_type: Option<String>,
}

/// LagoTrackedFs wraps LocalFs and emits notifications on write operations.
///
/// Notifications are sent to an async task that appends events to the Lago journal.
/// If the channel is full, the notification is dropped with a warning (degraded mode).
pub struct LagoTrackedFs {
    local_fs: LocalFs,
    blob_store: Arc<BlobStore>,
    tx: mpsc::Sender<FsWriteNotification>,
}

impl LagoTrackedFs {
    pub fn new(
        local_fs: LocalFs,
        blob_store: Arc<BlobStore>,
        tx: mpsc::Sender<FsWriteNotification>,
    ) -> Self {
        Self {
            local_fs,
            blob_store,
            tx,
        }
    }
}

impl FsPort for LagoTrackedFs {
    fn workspace_root(&self) -> &Path {
        self.local_fs.workspace_root()
    }

    fn resolve(&self, path: &Path) -> praxis_core::error::PraxisResult<PathBuf> {
        self.local_fs.resolve(path)
    }

    fn resolve_for_write(&self, path: &Path) -> praxis_core::error::PraxisResult<PathBuf> {
        self.local_fs.resolve_for_write(path)
    }

    fn read_to_string(&self, path: &Path) -> praxis_core::error::PraxisResult<String> {
        self.local_fs.read_to_string(path)
    }

    fn read_bytes(&self, path: &Path) -> praxis_core::error::PraxisResult<Vec<u8>> {
        self.local_fs.read_bytes(path)
    }

    fn write(&self, path: &Path, content: &[u8]) -> praxis_core::error::PraxisResult<()> {
        // 1. Write to filesystem
        self.local_fs.write(path, content)?;

        // 2. Hash content and store blob (sync operation)
        let blob_hash = self.blob_store.put(content)
            .map_err(|e| praxis_core::error::PraxisError::IoError(
                std::io::Error::new(std::io::ErrorKind::Other, e.to_string())
            ))?;

        // 3. Determine content type (simple heuristic)
        let content_type = path
            .extension()
            .and_then(|ext| ext.to_str())
            .map(|ext| match ext {
                "md" | "txt" => "text/plain".to_string(),
                "rs" => "text/x-rust".to_string(),
                "json" => "application/json".to_string(),
                _ => format!("application/x-{ext}"),
            });

        // 4. Compute relative path
        let relative_path = self.local_fs.relative(path)
            .unwrap_or_else(|| path.to_path_buf());

        // 5. Send notification (non-blocking try_send)
        let notification = FsWriteNotification {
            path: relative_path,
            blob_hash,
            size_bytes: content.len() as u64,
            content_type,
        };

        if let Err(e) = self.tx.try_send(notification) {
            warn!(
                path = %path.display(),
                error = %e,
                "LagoTrackedFs: notification channel full, dropped write event (degraded mode)"
            );
        } else {
            debug!(path = %path.display(), hash = %blob_hash, "LagoTrackedFs: write tracked");
        }

        Ok(())
    }

    fn exists(&self, path: &Path) -> bool {
        self.local_fs.exists(path)
    }

    fn metadata(&self, path: &Path) -> praxis_core::error::PraxisResult<FsMetadata> {
        self.local_fs.metadata(path)
    }

    fn read_dir(&self, path: &Path) -> praxis_core::error::PraxisResult<Vec<FsDirEntry>> {
        self.local_fs.read_dir(path)
    }

    fn create_dir_all(&self, path: &Path) -> praxis_core::error::PraxisResult<()> {
        self.local_fs.create_dir_all(path)
    }

    fn relative(&self, absolute_path: &Path) -> Option<PathBuf> {
        self.local_fs.relative(absolute_path)
    }
}

/// Background task that receives write notifications and appends events to the journal
pub async fn run_event_writer(
    mut rx: mpsc::Receiver<FsWriteNotification>,
    journal: Arc<dyn Journal>,
    session_id: SessionId,
    branch_id: BranchId,
) {
    debug!("LagoTrackedFs event writer started");

    while let Some(notification) = rx.recv().await {
        let payload = EventPayload::FileWrite {
            path: notification.path.display().to_string(),
            blob_hash: notification.blob_hash.into(),
            size_bytes: notification.size_bytes,
            content_type: notification.content_type,
        };

        let envelope = EventEnvelope {
            event_id: EventId::new(),
            session_id: session_id.clone(),
            branch_id: branch_id.clone(),
            run_id: None,
            seq: 0,
            timestamp: EventEnvelope::now_micros(),
            parent_id: None,
            payload,
            metadata: std::collections::HashMap::new(),
            schema_version: 1,
        };

        if let Err(e) = journal.append(envelope).await {
            warn!(
                path = %notification.path.display(),
                error = %e,
                "LagoTrackedFs: failed to append FileWrite event to journal"
            );
        } else {
            debug!(
                path = %notification.path.display(),
                hash = %notification.blob_hash,
                "LagoTrackedFs: FileWrite event persisted"
